  1→package cmd
  2→
  3→import (
  4→	"fmt"
  5→	"os"
  6→	"path/filepath"
  7→	"strings"
  8→
  9→	"github.com/spf13/cobra"
 10→	"github.com/usenurge/nurgesh/internal/account"
 11→	"github.com/usenurge/nurgesh/internal/project"
 12→)
 13→
 14→var (
 15→	buildVersion = "dev"
 16→	buildCommit  = "none"
 17→	buildDate    = "unknown"
 18→)
 19→
 20→var convexSiteURL = ""
 21→
 22→// SetVersion sets the build version info from ldflags.
 23→func SetVersion(version, commit, date string) {
 24→	buildVersion = version
 25→	buildCommit = commit
 26→	buildDate = date
 27→}
 28→
 29→// SetConvexURL sets the Convex deployment URL from ldflags.
 30→func SetConvexURL(url string) {
 31→	convexSiteURL = url
 32→}
 33→
 34→// GetConvexURL returns the Convex site URL, allowing env var override for development.
 35→func GetConvexURL() string {
 36→	if env := os.Getenv("NURGE_CONVEX_URL"); env != "" {
 37→		return env
 38→	}
 39→	return convexSiteURL
 40→}
 41→
 42→// GetDashboardURL returns the dashboard URL, allowing env var override for development.
 43→func GetDashboardURL() string {
 44→	if env := os.Getenv("NURGE_DASHBOARD_URL"); env != "" {
 45→		return env
 46→	}
 47→	return "https://app.nurge.sh"
 48→}
 49→
 50→var (
 51→	initForce     bool
 52→	initSkipHooks bool
 53→	initVerbose   bool
 54→)
 55→
 56→var rootCmd = &cobra.Command{
 57→	Use:   "nurge [directory]",
 58→	Short: "nurge — outbound that learns",
 59→	Long:  "Nurge is an outbound sales tool that learns from your sent email history.\n\nRun 'nurge <directory>' to create a new project, or 'nurge' in an empty directory to initialize it.",
 60→	RunE:  runInit,
 61→}
 62→
 63→var versionCmd = &cobra.Command{
 64→	Use:         "version",
 65→	Short:       "Print the version of nurge",
 66→	Annotations: map[string]string{"skipAuth": "true"},
 67→	Run: func(cmd *cobra.Command, args []string) {
 68→		fmt.Printf("nurge %s (commit: %s, built: %s)\n", buildVersion, buildCommit, buildDate)
 69→	},
 70→}
 71→
 72→// runInit is the shared init logic used by both the root command and the hidden init alias.
 73→func runInit(cmd *cobra.Command, args []string) error {
 74→	dirCreated := ""
 75→
 76→	if len(args) == 1 {
 77→		dir := args[0]
 78→		if err := os.MkdirAll(dir, 0755); err != nil {
 79→			return fmt.Errorf("failed to create directory %s: %w", dir, err)
 80→		}
 81→		abs, err := filepath.Abs(dir)
 82→		if err != nil {
 83→			return err
 84→		}
 85→		if err := os.Chdir(abs); err != nil {
 86→			return fmt.Errorf("failed to enter directory %s: %w", dir, err)
 87→		}
 88→		dirCreated = dir
 89→	} else if !initForce {
 90→		// No directory arg: only init if current dir is empty or already initialized
 91→		empty, _ := project.IsDirEmpty(".")
 92→		alreadyInit := project.IsNurgeProject(".")
 93→		if !empty && !alreadyInit {
 94→			return cmd.Help()
 95→		}
 96→	}
 97→
 98→	// Check if current directory is non-empty (unless --force)
 99→	if !initForce {
100→		empty, err := project.IsDirEmpty(".")
101→		if err != nil {
102→			return err
103→		}
104→		if !empty && !project.IsNurgeProject(".") {
105→			return fmt.Errorf("this directory isn't empty. Run: nurge <folder-name>")
106→		}
107→	}
108→
109→	opts := project.Options{
110→		SkipHooks: initSkipHooks,
111→		Force:     initForce,
112→		Verbose:   initVerbose,
113→	}
114→	if err := project.Run(opts); err != nil {
115→		return err
116→	}
117→
118→	if dirCreated != "" {
119→		fmt.Println()
120→		fmt.Printf("  Now run: cd %s\n", dirCreated)
121→		fmt.Println()
122→	}
123→
124→	return nil
125→}
126→
127→// shouldSkipAuth walks the command tree to check if any command in the
128→// chain has the skipAuth annotation. This handles cases like
129→// "nurge account login" where account has skipAuth.
130→func shouldSkipAuth(cmd *cobra.Command) bool {
131→	for c := cmd; c != nil; c = c.Parent() {
132→		if c.Annotations != nil && c.Annotations["skipAuth"] == "true" {
133→			return true
134→		}
135→	}
136→	return false
137→}
138→
139→func init() {
140→	rootCmd.AddCommand(versionCmd)
141→
142→	rootCmd.Flags().BoolVar(&initForce, "force", false, "Re-run all steps even if already completed")
143→	rootCmd.Flags().BoolVar(&initSkipHooks, "skip-hooks", false, "Skip Claude Code hook installation")
144→	rootCmd.Flags().BoolVar(&initVerbose, "verbose", false, "Show detailed output")
145→
146→	rootCmd.PersistentPreRunE = func(cmd *cobra.Command, args []string) error {
147→		// Root command (init) skips auth — it's the first thing a user runs
148→		if cmd == rootCmd ||
149→			shouldSkipAuth(cmd) ||
150→			cmd.Name() == "help" ||
151→			cmd.Name() == "completion" {
152→			return nil
153→		}
154→		_, err := account.EnsureAuth(GetConvexURL(), GetDashboardURL())
155→		return err
156→	}
157→}
158→
159→// isKnownCommand checks if name matches any registered subcommand.
160→func isKnownCommand(name string) bool {
161→	for _, c := range rootCmd.Commands() {
162→		if c.Name() == name {
163→			return true
164→		}
165→		for _, alias := range c.Aliases {
166→			if alias == name {
167→				return true
168→			}
169→		}
170→	}
171→	return name == "help" || name == "completion"
172→}
173→
174→func Execute() error {
175→	// Allow "nurge my-outbound" as shorthand for "nurge init my-outbound".
176→	// Cobra rejects unknown subcommands before RunE runs, so we rewrite args
177→	// when the first arg isn't a known subcommand or flag.
178→	if len(os.Args) > 1 {
179→		first := os.Args[1]
180→		if !strings.HasPrefix(first, "-") && !isKnownCommand(first) {
181→			os.Args = append([]string{os.Args[0], "init"}, os.Args[1:]...)
182→		}
183→	}
184→	return rootCmd.Execute()
185→}
