 15→const projectLocalDefs = ".nurge/connectors/definitions"
 16→
 17→var connectorsCmd = &cobra.Command{
 18→	Use:   "connectors",
 19→	Short: "List connected services",
 20→	RunE: func(cmd *cobra.Command, args []string) error {
 21→		cfg, err := project.Load()
 22→		if err != nil {
 23→			return fmt.Errorf("loading config: %w", err)
 24→		}
 25→
 26→		registry, err := connector.LoadRegistry(projectLocalDefs)
 27→		if err != nil {
 28→			return fmt.Errorf("loading registry: %w", err)
 29→		}
 30→
 31→		hasAny := false
 32→		for _, def := range registry {
 33→			cs, ok := cfg.Connectors[def.ID]
 34→			if !ok || !cs.Connected {
 35→				continue
 36→			}
 37→			hasAny = true
 38→			fmt.Printf("  \033[32m✓\033[0m %-10s %s\n", def.Name, cs.Account)
 39→		}
 40→
 41→		if !hasAny {
 42→			fmt.Println("  No connectors configured. Run `nurge connect gmail` to connect.")
 43→		}
 44→
 45→		return nil
 46→	},
 47→}
 48→
 49→// connectorsAvailableCmd lists ALL known connectors grouped by type, with connection status.
 50→var connectorsAvailableCmd = &cobra.Command{
 51→	Use:   "available",
 52→	Short: "List all available connectors (bundled + project-local)",
 53→	RunE: func(cmd *cobra.Command, args []string) error {
 54→		// Config is optional — if not in a project dir, just omit status.
 55→		cfg, _ := project.Load()
 56→
 57→		registry, err := connector.LoadRegistry(projectLocalDefs)
 58→		if err != nil {
 59→			return fmt.Errorf("loading registry: %w", err)
 60→		}
 61→
 62→		// Group by type.
 63→		groups := map[string][]connector.ConnectorDef{}
 64→		order := []string{}
 65→		seen := map[string]bool{}
 66→		for _, def := range registry {
 67→			if !seen[def.Type] {
 68→				seen[def.Type] = true
 69→				order = append(order, def.Type)
 70→			}
 71→			groups[def.Type] = append(groups[def.Type], def)
 72→		}
 73→
 74→		for _, typ := range order {
 75→			// Capitalise the type heading.
 76→			heading := strings.ToUpper(typ[:1]) + typ[1:]
 77→			fmt.Printf("  %s\n", heading)
 78→			for _, def := range groups[typ] {
 79→				requiredMark := ""
 80→				if def.Required {
 81→					requiredMark = " *"
 82→				}
 83→				statusSuffix := ""
 84→				if cfg != nil {
 85→					if cs, ok := cfg.Connectors[def.ID]; ok && cs.Connected {
 86→						statusSuffix = fmt.Sprintf(" (connected: %s)", cs.Account)
 87→					}
 88→				}
 89→				fmt.Printf("    %-15s %-20s%s%s\n", def.ID, def.Name, requiredMark, statusSuffix)
 90→			}
 91→		}
 92→
 93→		return nil
 94→	},
 95→}
 96→
 97→// connectorsValidateCmd validates a connector YAML file.
 98→var connectorsValidateCmd = &cobra.Command{
 99→	Use:   "validate <file>",
100→	Short: "Validate a connector YAML definition file",
101→	Args:  cobra.ExactArgs(1),
102→	RunE: func(cmd *cobra.Command, args []string) error {
103→		path := args[0]
104→		data, err := os.ReadFile(path)
105→		if err != nil {
106→			return fmt.Errorf("reading file %q: %w", path, err)
107→		}
108→
109→		def, err := connector.ParseYAML(data)
110→		if err != nil {
111→			fmt.Printf("invalid: %s\n  %v\n", path, err)
112→			return err
113→		}
114→
115→		fmt.Printf("valid: %s (id=%s, type=%s, auth=%s)\n", path, def.ID, def.Type, def.Auth.Method)
116→		return nil
117→	},
118→}
