120→// connectorsInfoFormat is the --format flag for the info subcommand.
121→var connectorsInfoFormat string
122→
123→// infoOutput is used for JSON marshalling of connector info.
124→type infoOutput struct {
125→	ID         string      `json:"id"`
126→	Name       string      `json:"name"`
127→	Type       string      `json:"type"`
128→	Tier       int         `json:"tier"`
129→	Required   bool        `json:"required"`
130→	AuthMethod string      `json:"auth_method"`
131→	Proxy      proxyOutput `json:"proxy"`
132→}
133→
134→type proxyOutput struct {
135→	BaseURL    string `json:"base_url"`
136→	AuthHeader string `json:"auth_header"`
137→}
138→
139→// connectorsInfoCmd looks up a connector by ID and prints its details.
140→var connectorsInfoCmd = &cobra.Command{
141→	Use:   "info <id>",
142→	Short: "Show details for a connector",
143→	Args:  cobra.ExactArgs(1),
144→	RunE: func(cmd *cobra.Command, args []string) error {
145→		id := args[0]
146→
147→		registry, err := connector.LoadRegistry(projectLocalDefs)
148→		if err != nil {
149→			return fmt.Errorf("loading registry: %w", err)
150→		}
151→
152→		var found *connector.ConnectorDef
153→		for i := range registry {
154→			if registry[i].ID == id {
155→				found = &registry[i]
156→				break
157→			}
158→		}
159→		if found == nil {
160→			return fmt.Errorf("connector %q not found", id)
161→		}
162→
163→		out := infoOutput{
164→			ID:         found.ID,
165→			Name:       found.Name,
166→			Type:       found.Type,
167→			Tier:       found.Tier,
168→			Required:   found.Required,
169→			AuthMethod: found.Def.Auth.Method,
170→			Proxy: proxyOutput{
171→				BaseURL:    found.Def.Proxy.BaseURL,
172→				AuthHeader: found.Def.Proxy.AuthHeader,
173→			},
174→		}
175→
176→		if connectorsInfoFormat == "json" {
177→			enc := json.NewEncoder(os.Stdout)
178→			enc.SetIndent("", "  ")
179→			return enc.Encode(out)
180→		}
181→
182→		// Plain text output.
183→		fmt.Printf("ID:          %s\n", out.ID)
184→		fmt.Printf("Name:        %s\n", out.Name)
185→		fmt.Printf("Type:        %s\n", out.Type)
186→		fmt.Printf("Tier:        %d\n", out.Tier)
187→		fmt.Printf("Required:    %v\n", out.Required)
188→		fmt.Printf("Auth method: %s\n", out.AuthMethod)
189→		if out.Proxy.BaseURL != "" {
190→			fmt.Printf("Proxy URL:   %s\n", out.Proxy.BaseURL)
191→		}
192→		return nil
193→	},
194→}
195→
196→// connectorsAddFile is the --file flag for the add subcommand.
197→var connectorsAddFile string
198→
199→// connectorsAddCmd validates a YAML file and installs it into the project-local definitions dir.
200→var connectorsAddCmd = &cobra.Command{
201→	Use:   "add",
202→	Short: "Add a project-local connector definition",
203→	RunE: func(cmd *cobra.Command, args []string) error {
204→		if connectorsAddFile == "" {
205→			return fmt.Errorf("--file is required")
206→		}
207→
208→		data, err := os.ReadFile(connectorsAddFile)
209→		if err != nil {
210→			return fmt.Errorf("reading file %q: %w", connectorsAddFile, err)
211→		}
212→
213→		def, err := connector.ParseYAML(data)
214→		if err != nil {
215→			return fmt.Errorf("invalid connector definition: %w", err)
216→		}
217→
218→		destDir := projectLocalDefs
219→		if err := os.MkdirAll(destDir, 0755); err != nil {
220→			return fmt.Errorf("creating definitions directory: %w", err)
221→		}
222→
223→		dest := filepath.Join(destDir, def.ID+".yaml")
224→		if err := os.WriteFile(dest, data, 0644); err != nil {
225→			return fmt.Errorf("writing definition: %w", err)
226→		}
227→
228→		fmt.Printf("\033[32m✓\033[0m Connector %q added to %s\n", def.ID, dest)
229→		return nil
230→	},
231→}
232→
233→func init() {
234→	// info --format flag
235→	connectorsInfoCmd.Flags().StringVar(&connectorsInfoFormat, "format", "", "Output format: json or plain (default)")
236→
237→	// add --file flag
238→	connectorsAddCmd.Flags().StringVar(&connectorsAddFile, "file", "", "Path to connector YAML definition file")
239→
240→	connectorsCmd.AddCommand(connectorsAvailableCmd)
241→	connectorsCmd.AddCommand(connectorsValidateCmd)
242→	connectorsCmd.AddCommand(connectorsInfoCmd)
243→	connectorsCmd.AddCommand(connectorsAddCmd)
244→
245→	rootCmd.AddCommand(connectorsCmd)
246→}
