57→var learnListCmd = &cobra.Command{
58→	Use:   "list",
59→	Short: "List all learnings",
60→	RunE: func(cmd *cobra.Command, args []string) error {
61→		d, err := db.Open()
62→		if err != nil {
63→			return err
64→		}
65→		defer d.Close()
