 77→// sessionStatus holds workspace state gathered for banner/prompt output.
 78→type sessionStatus struct {
 79→	configLoaded   bool
 80→	setupCompleted bool
 81→	connectors     map[string]project.ConnectorState
 82→	settings       map[string]string
 83→	emailTotal     int
 84→	outboundTotal  int
 85→	weeklyStats    *email.WeeklyStats
 86→	skillCount     int
 87→	skillNames     []string
 88→	contactCount   int
 89→	learningCount  int
 90→}
 91→
 92→func gatherStatus() *sessionStatus {
 93→	s := &sessionStatus{
 94→		settings: make(map[string]string),
 95→	}
 96→
 97→	// Load config (graceful — may not exist)
 98→	cfg, err := project.Load()
 99→	if err == nil {
100→		s.configLoaded = true
101→		s.setupCompleted = cfg.SetupCompleted
102→		s.connectors = cfg.Connectors
103→		if cfg.Settings != nil {
104→			s.settings = cfg.Settings
105→		}
106→	}
107→
108→	// Load DB stats (graceful — may not exist)
109→	if !db.Exists() {
110→		return s
111→	}
112→	d, err := db.Open()
113→	if err != nil {
114→		return s
115→	}
116→	defer d.Close()
117→
118→	stats, err := email.Stats(d)
119→	if err == nil {
120→		s.emailTotal = stats.Total
121→		s.outboundTotal = stats.ByClass["outbound"]
122→	}
123→
124→	weekly, err := email.ThisWeek(d)
125→	if err == nil {
126→		s.weeklyStats = weekly
127→	}
128→
129→	skills, err := session.ListSkills(d)
130→	if err == nil {
131→		s.skillCount = len(skills)
132→		for _, sk := range skills {
133→			s.skillNames = append(s.skillNames, sk.SkillName)
134→		}
135→	}
136→
137→	// Contact count (graceful)
138→	d.QueryRow("SELECT COUNT(*) FROM contacts").Scan(&s.contactCount)
139→
140→	// Learning count (graceful)
141→	d.QueryRow("SELECT COUNT(*) FROM learnings").Scan(&s.learningCount)
142→
143→	return s
144→}
145→
146→// hookOutput is the JSON structure Claude Code expects from hook stdout.
147→type hookOutput struct {
148→	SystemMessage    string            `json:"systemMessage,omitempty"`
149→	HookSpecificOut  *hookSpecificOut  `json:"hookSpecificOutput,omitempty"`
150→}
151→
152→type hookSpecificOut struct {
153→	HookEventName     string `json:"hookEventName"`
154→	AdditionalContext string `json:"additionalContext,omitempty"`
155→}
156→
157→// runSessionStart outputs JSON with systemMessage (visible banner) and
158→// additionalContext (LLM context) for the SessionStart hook.
159→// Also captures the session in DB + log.
160→func runSessionStart() error {
161→	// Read stdin (Claude Code sends session info)
162→	input, _ := session.ReadStdin()
163→
164→	// Capture session in DB (graceful — don't fail the hook if DB is missing)
165→	if input != nil && input.SessionID != "" && db.Exists() {
166→		if d, err := db.Open(); err == nil {
167→			db.EnsureSessionTables(d)
168→			session.CreateSession(d, input.SessionID, input.Model, input.Source, input.TranscriptPath)
169→			session.AddEvent(d, input.SessionID, "session_start", input)
170→			d.Close()
171→		}
172→		session.Logger().Info("session-start", "session_id", input.SessionID, "model", input.Model)
173→		session.FlushLog()
174→	}
175→
176→	// Sync permissions — ensures existing users get any new permissions
177→	// added in later versions. Graceful — never fails the hook.
178→	project.SyncPermissions()
179→
180→	// Auto-update check (non-blocking, cached)
181→	updateMsg := checkAndAutoUpdate()
182→
183→	s := gatherStatus()
184→
185→	banner := buildBanner(s)
186→	if updateMsg != "" {
187→		banner += "\n  " + updateMsg
188→	}
189→	context := buildPromptContext(s)
190→
191→	out := hookOutput{
192→		SystemMessage: banner,
193→		HookSpecificOut: &hookSpecificOut{
194→			HookEventName:     "SessionStart",
195→			AdditionalContext: context,
196→		},
197→	}
198→
199→	enc := json.NewEncoder(os.Stdout)
200→	return enc.Encode(out)
201→}
202→
203→// runUserPrompt captures a user prompt submission event.
204→func runUserPrompt() error {
205→	input, err := session.ReadStdin()
206→	if err != nil || input == nil || input.SessionID == "" {
207→		return nil // graceful no-op
208→	}
209→
210→	if !db.Exists() {
211→		return nil
212→	}
213→	d, err := db.Open()
214→	if err != nil {
215→		return nil
216→	}
217→	defer d.Close()
218→
219→	db.EnsureSessionTables(d)
220→	session.AddEvent(d, input.SessionID, "prompt", input)
221→
222→	// Log without prompt content — keep logs lightweight
223→	session.Logger().Info("prompt", "session_id", input.SessionID)
224→	session.FlushLog()
225→	return nil
226→}
227→
228→// runStop captures a stop event and creates a checkpoint.
229→func runStop() error {
230→	input, err := session.ReadStdin()
231→	if err != nil || input == nil || input.SessionID == "" {
232→		return nil
233→	}
234→
235→	if !db.Exists() {
236→		return nil
237→	}
238→	d, err := db.Open()
239→	if err != nil {
240→		return nil
241→	}
242→	defer d.Close()
243→
244→	db.EnsureSessionTables(d)
245→	session.AddEvent(d, input.SessionID, "stop", input)
246→	if len(input.ModifiedFiles) > 0 {
247→		session.AddCheckpoint(d, input.SessionID, input.ModifiedFiles)
248→	}
249→
250→	session.Logger().Info("stop", "session_id", input.SessionID, "reason", input.StopReason)
251→	session.FlushLog()
252→	return nil
253→}
254→
255→// runSessionEnd marks a session as ended.
256→func runSessionEnd() error {
257→	input, err := session.ReadStdin()
258→	if err != nil || input == nil || input.SessionID == "" {
259→		return nil
260→	}
261→
262→	if !db.Exists() {
263→		return nil
264→	}
265→	d, err := db.Open()
266→	if err != nil {
267→		return nil
268→	}
269→	defer d.Close()
270→
271→	db.EnsureSessionTables(d)
272→	session.EndSession(d, input.SessionID)
273→	session.AddEvent(d, input.SessionID, "session_end", input)
274→
275→	session.Logger().Info("session-end", "session_id", input.SessionID)
276→	session.FlushLog()
277→	return nil
278→}
