280→func buildBanner(s *sessionStatus) string {
281→	var b strings.Builder
282→	ver := fmt.Sprintf("nurge %s", buildVersion)
283→
284→	// Line 1: Powered by Nurge
285→	b.WriteString("\n\nPowered by Nurge\n")
286→	// Line 2: Version
287→	fmt.Fprintf(&b, "  %s\n", ver)
288→
289→	if !s.configLoaded {
290→		b.WriteString("  Run: nurge to get started")
291→		return b.String()
292→	}
293→
294→	// --- Pre-setup: no connectors yet ---
295→	hasConnectors := false
296→	for _, c := range s.connectors {
297→		if c.Connected {
298→			hasConnectors = true
299→			break
300→		}
301→	}
302→	if !hasConnectors {
303→		b.WriteString("  Run /nurge:setup to connect your email and get started.")
304→		return b.String()
305→	}
306→
307→	// --- Setup in progress ---
308→	if !s.setupCompleted {
309→		name := s.settings["user.name"]
310→		if name != "" {
311→			fmt.Fprintf(&b, "  Hey %s, setup in progress.\n", name)
312→		} else {
313→			b.WriteString("  Setup in progress.\n")
314→		}
315→		b.WriteString("  Run /nurge:setup to continue where you left off.")
316→		return b.String()
317→	}
318→
319→	// --- Post-setup: compact rotating dashboard ---
320→	name := s.settings["user.name"]
321→	if name != "" {
322→		fmt.Fprintf(&b, "  Hey %s\n", name)
323→	}
324→
325→	// Always show: KPI progress (the one thing that matters most)
326→	if s.weeklyStats != nil && s.weeklyStats.OutboundSent > 0 {
327→		fmt.Fprintf(&b, "  This week: %d emails sent", s.weeklyStats.OutboundSent)
328→		if s.weeklyStats.UniqueContacts > 0 {
329→			fmt.Fprintf(&b, " → %d contacts", s.weeklyStats.UniqueContacts)
330→		}
331→		kpiTarget := s.settings["kpi.daily_emails"]
332→		if kpiTarget != "" {
333→			fmt.Fprintf(&b, " (target: %s/day)", kpiTarget)
334→		}
335→		b.WriteString("\n")
336→	} else {
337→		goal := s.settings["kpi.goal"]
338→		if goal != "" {
339→			fmt.Fprintf(&b, "  Goal: %s — no emails sent this week yet\n", goal)
340→		}
341→	}
342→
343→	// Rotate one additional insight based on day-of-year
344→	// This keeps the banner fresh without overwhelming
345→	slot := time.Now().YearDay() % 5
346→	switch slot {
347→	case 0: // Sending health
348→		warmup := s.settings["sending.warmup_status"]
349→		domainType := s.settings["sending.domain_type"]
350→		if warmup == "fresh" {
351→			b.WriteString("  Domain is fresh — warmup in progress, conservative limits active\n")
352→		} else if domainType == "primary" {
353→			b.WriteString("  Sending from primary domain — consider a dedicated outbound domain\n")
354→		} else {
355→			fmt.Fprintf(&b, "  %s emails synced | %d skills active\n", formatCount(s.emailTotal), s.skillCount)
356→		}
357→	case 1: // Data snapshot
358→		fmt.Fprintf(&b, "  Data: %s emails", formatCount(s.emailTotal))
359→		if s.outboundTotal > 0 {
360→			fmt.Fprintf(&b, " (%d outbound)", s.outboundTotal)
361→		}
362→		if s.contactCount > 0 {
363→			fmt.Fprintf(&b, " | %d contacts", s.contactCount)
364→		}
365→		b.WriteString("\n")
366→	case 2: // Learnings
367→		if s.learningCount > 0 {
368→			fmt.Fprintf(&b, "  %d learnings captured — skills improving with every session\n", s.learningCount)
369→		} else {
370→			fmt.Fprintf(&b, "  %d skills active | Start sending to build learnings\n", s.skillCount)
371→		}
372→	case 3: // Connected services
373→		var connList []string
374→		for id, c := range s.connectors {
375→			if c.Connected {
376→				connList = append(connList, capitalize(id))
377→			}
378→		}
379→		fmt.Fprintf(&b, "  Connected: %s | %d skills active\n", strings.Join(connList, ", "), s.skillCount)
380→	case 4: // Quick action suggestion
381→		actions := []string{
382→			"\"research [company]\" — deep-dive a prospect",
383→			"\"write an email to [persona] at [company]\"",
384→			"\"/nurge:review\" — check your KPI progress",
385→			"\"show my pipeline\" — see what needs attention",
386→		}
387→		pick := time.Now().YearDay() / 5 % len(actions)
388→		fmt.Fprintf(&b, "  Try: %s\n", actions[pick])
389→	}
390→
391→	return b.String()
392→}
