394→func buildPromptContext(s *sessionStatus) string {
395→	var b strings.Builder
396→
397→	if !s.configLoaded || !s.setupCompleted {
398→		b.WriteString("You are in a Nurge workspace. Setup is not complete. ")
399→		b.WriteString("Guide the user to run /nurge:setup to finish configuration. ")
400→		b.WriteString("Do not attempt to use nurge data commands — they will have no data yet.")
401→		return b.String()
402→	}
403→
404→	// User context
405→	name := s.settings["user.name"]
406→	role := s.settings["user.role"]
407→	if name != "" {
408→		fmt.Fprintf(&b, "User: %s", name)
409→		if role != "" {
410→			fmt.Fprintf(&b, " (%s)", role)
411→		}
412→		b.WriteString("\n")
413→	}
414→
415→	b.WriteString("You are in a Nurge outbound sales workspace.\n")
416→	fmt.Fprintf(&b, "Status: Setup complete. %s emails synced (%d outbound). %d contacts. %d skills active.\n",
417→		formatCount(s.emailTotal), s.outboundTotal, s.contactCount, s.skillCount)
418→
419→	// KPI context
420→	goal := s.settings["kpi.goal"]
421→	dailyTarget := s.settings["kpi.daily_emails"]
422→	weeklyMeetings := s.settings["kpi.weekly_meetings"]
423→	if goal != "" {
424→		fmt.Fprintf(&b, "Outbound goal: %s.", goal)
425→		if dailyTarget != "" {
426→			fmt.Fprintf(&b, " Daily target: %s emails.", dailyTarget)
427→		}
428→		if weeklyMeetings != "" {
429→			fmt.Fprintf(&b, " Weekly meeting target: %s.", weeklyMeetings)
430→		}
431→		b.WriteString("\n")
432→	}
433→
434→	// Sending context
435→	warmup := s.settings["sending.warmup_status"]
436→	domainType := s.settings["sending.domain_type"]
437→	if warmup == "fresh" {
438→		b.WriteString("IMPORTANT: Domain is fresh/not warmed up. Enforce conservative sending limits. Do not exceed daily target.\n")
439→	}
440→	if domainType == "primary" {
441→		b.WriteString("Note: User is sending from primary business domain. Be conservative with volume.\n")
442→	}
443→
444→	// Geography / compliance
445→	geo := s.settings["prospects.geography"]
446→	if geo != "" {
447→		fmt.Fprintf(&b, "Prospect geography: %s.", geo)
448→		if strings.Contains(strings.ToLower(geo), "eu") || strings.Contains(strings.ToLower(geo), "europe") {
449→			b.WriteString(" GDPR applies — ensure legitimate interest basis for outreach.")
450→		}
451→		b.WriteString("\n")
452→	}
453→
454→	// Rules
455→	b.WriteString("Rules:\n")
456→	b.WriteString("- Use `nurge` CLI commands for all data access. Never read .nurge/ directly.\n")
457→	b.WriteString("- For ICP, personas, and product context: nurge config show --format json\n")
458→	b.WriteString("- For email patterns and insights: nurge context generate --format json\n")
459→	b.WriteString("- For email stats: nurge emails stats --format json\n")
460→	b.WriteString("- When sending emails: nurge send (always get user approval first)\n")
461→	b.WriteString("- When researching prospects: use WebSearch with multiple angles, check company legal pages (mentions légales, impressum), cross-reference before drafting")
462→
463→	if len(s.skillNames) > 0 {
464→		fmt.Fprintf(&b, "\nAvailable skills: %s", strings.Join(s.skillNames, ", "))
465→	}
466→
467→	return b.String()
468→}
