284→func preview(body string, limit int) string {
285→	body = strings.TrimSpace(body)
286→	body = strings.ReplaceAll(body, "\n", " ")
287→	if limit <= 0 || len(body) <= limit {
288→		return body
289→	}
290→	return body[:limit-1] + "…"
291→}
292→
293→func dispatchSubject(item sequence.DispatchTask) string {
294→	if strings.TrimSpace(item.RenderedSubject) != "" {
295→		return strings.TrimSpace(item.RenderedSubject)
296→	}
297→	return strings.TrimSpace(item.Subject)
298→}
