301→	dispatcherCmd.PersistentFlags().StringVar(&dispatcherFormat, "format", "", "Output format (json)")
302→	dispatcherRunCmd.Flags().IntVar(&dispatcherLimit, "limit", 0, "Max results")
303→	dispatcherRunCmd.Flags().BoolVar(&dispatcherSyncReplies, "sync-replies", true, "Sync active-thread replies before evaluating the queue")
304→	dispatcherRunCmd.Flags().BoolVar(&dispatcherExecute, "execute", false, "Render and send ready tasks automatically")
305→	dispatcherRunCmd.Flags().StringVar(&dispatcherTransportEmail, "transport-email", "", "Transport mailbox to use for execution/rotation (defaults to connected Gmail account)")
306→	dispatcherCmd.AddCommand(dispatcherRunCmd)
307→	rootCmd.AddCommand(dispatcherCmd)
308→}
