115→		if err := sequence.SetCampaignStatus(d, args[0], "active"); err != nil {
116→			return err
117→		}
118→		fmt.Printf("  ✓ Resumed campaign %s\n", args[0])
119→		return nil
120→	},
121→}
122→
123→func init() {
124→	campaignsCmd.PersistentFlags().StringVar(&campaignsFormat, "format", "", "Output format (json)")
125→	campaignsListCmd.Flags().StringVar(&campaignsStatus, "status", "", "Filter by status")
126→	campaignsListCmd.Flags().IntVar(&campaignsLimit, "limit", 50, "Max results")
127→	campaignsCreateCmd.Flags().StringVar(&campaignSequence, "sequence", "", "Sequence template for this campaign")
128→	campaignsCreateCmd.Flags().StringVar(&campaignMailbox, "mailbox", "", "Default mailbox email for the campaign")
129→	campaignsCreateCmd.Flags().StringVar(&campaignDescription, "description", "", "Optional campaign description")
130→	campaignsCmd.AddCommand(campaignsCreateCmd)
131→	campaignsCmd.AddCommand(campaignsListCmd)
132→	campaignsCmd.AddCommand(campaignsPauseCmd)
133→	campaignsCmd.AddCommand(campaignsResumeCmd)
134→	rootCmd.AddCommand(campaignsCmd)
135→}
