  1→package connector
  2→
  3→import (
  4→	"fmt"
  5→
  6→	"gopkg.in/yaml.v3"
  7→)
  8→
  9→// YAMLConnector is the parsed representation of a connector YAML file.
 10→type YAMLConnector struct {
 11→	SchemaVersion int          `yaml:"schema_version"`
 12→	ID            string       `yaml:"id"`
 13→	Name          string       `yaml:"name"`
 14→	Type          string       `yaml:"type"`
 15→	Tier          int          `yaml:"tier"`
 16→	Required      bool         `yaml:"required"`
 17→	Description   string       `yaml:"description"`
 18→	Icon          string       `yaml:"icon"`
 19→	Auth          AuthConfig   `yaml:"auth"`
 20→	Credentials   CredConfig   `yaml:"credentials"`
 21→	Verify        VerifyConfig `yaml:"verify"`
 22→	Proxy         ProxyConfig  `yaml:"proxy"`
 23→}
 24→
 25→// AuthConfig describes how to authenticate with the service.
 26→type AuthConfig struct {
 27→	Method       string            `yaml:"method"` // oauth2, api_key, basic, webhook
 28→	AuthorizeURL string            `yaml:"authorize_url"`
 29→	TokenURL     string            `yaml:"token_url"`
 30→	Scopes       []string          `yaml:"scopes"`
 31→	AuthStyle    string            `yaml:"auth_style"`   // in_params, in_header
 32→	ExtraParams  map[string]string `yaml:"extra_params"`
 33→	// api_key fields
 34→	Header     string `yaml:"header"`
 35→	QueryParam string `yaml:"query_param"`
 36→	EnvVar     string `yaml:"env_var"`
 37→	// basic auth fields
 38→	UsernameVar string `yaml:"username_var"`
 39→	PasswordVar string `yaml:"password_var"`
 40→	// webhook fields
 41→	URLVar string `yaml:"url_var"`
 42→}
 43→
 44→// CredFallback is one entry in the credential fallback chain.
 45→type CredFallback struct {
 46→	Source string `yaml:"source"`
 47→}
 48→
 49→// CredConfig describes where credentials come from.
 50→type CredConfig struct {
 51→	Source          string         `yaml:"source"` // env, bundled, google_json, file, prompt
 52→	ClientIDVar     string         `yaml:"client_id_var"`
 53→	ClientSecretVar string         `yaml:"client_secret_var"`
 54→	Fallback        []CredFallback `yaml:"fallback"`
 55→}
 56→
 57→// VerifyConfig describes the connection verification call.
 58→type VerifyConfig struct {
 59→	URL           string            `yaml:"url"`
 60→	Method        string            `yaml:"method"`
 61→	Headers       map[string]string `yaml:"headers"`
 62→	AccountFields []string          `yaml:"account_fields"`
 63→	AccountLabel  string            `yaml:"account_label"`
 64→}
 65→
 66→// ProxyConfig describes how to call the service's API.
 67→type ProxyConfig struct {
 68→	BaseURL    string `yaml:"base_url"`
 69→	AuthHeader string `yaml:"auth_header"`
 70→}
 71→
 72→// ParseYAML parses and validates a connector YAML definition.
 73→func ParseYAML(data []byte) (*YAMLConnector, error) {
 74→	var def YAMLConnector
 75→	if err := yaml.Unmarshal(data, &def); err != nil {
 76→		return nil, fmt.Errorf("parsing YAML: %w", err)
 77→	}
 78→	if err := validateDef(&def); err != nil {
 79→		return nil, err
 80→	}
 81→	// Defaults
 82→	if def.Tier == 0 {
 83→		def.Tier = 2
 84→	}
 85→	if def.Verify.Method == "" {
 86→		def.Verify.Method = "GET"
 87→	}
 88→	return &def, nil
 89→}
 90→
 91→func validateDef(d *YAMLConnector) error {
 92→	if d.SchemaVersion != 1 {
 93→		return fmt.Errorf("connector definition has unsupported schema_version: %d (expected 1)", d.SchemaVersion)
 94→	}
 95→	if d.ID == "" {
 96→		return fmt.Errorf("connector definition missing required field: id")
 97→	}
 98→	if d.Name == "" {
 99→		return fmt.Errorf("connector %q missing required field: name", d.ID)
100→	}
101→	if d.Type == "" {
102→		return fmt.Errorf("connector %q missing required field: type", d.ID)
103→	}
104→	if d.Auth.Method == "" {
105→		return fmt.Errorf("connector %q missing required field: auth.method", d.ID)
106→	}
107→
108→	switch d.Auth.Method {
109→	case "oauth2":
110→		if d.Auth.AuthorizeURL == "" {
111→			return fmt.Errorf("connector %q (oauth2) missing auth.authorize_url", d.ID)
112→		}
113→		if d.Auth.TokenURL == "" {
114→			return fmt.Errorf("connector %q (oauth2) missing auth.token_url", d.ID)
115→		}
116→	case "api_key":
117→		if d.Auth.Header == "" && d.Auth.QueryParam == "" {
118→			return fmt.Errorf("connector %q (api_key) missing auth.header or auth.query_param", d.ID)
119→		}
120→	case "basic":
121→		// valid — credentials resolved at connect time
122→	case "webhook":
123→		// valid — URL resolved at connect time
124→	default:
125→		return fmt.Errorf("connector %q has unknown auth.method: %q", d.ID, d.Auth.Method)
126→	}
127→
128→	return nil
129→}
