 5→type ClassifyUpdate struct {
 6→	ID           string  `json:"id"`
 7→	Class        string  `json:"class"`
 8→	Confidence   float64 `json:"confidence"`
 9→	ClassifiedBy string  `json:"classified_by"`
10→}
11→
12→func Classify(d *sql.DB, updates []ClassifyUpdate) (int, error) {
13→	tx, err := d.Begin()
14→	if err != nil {
15→		return 0, err
16→	}
17→	defer tx.Rollback()
18→
19→	stmt, err := tx.Prepare("UPDATE emails SET class = ?, class_confidence = ?, classified_by = ? WHERE id = ?")
20→	if err != nil {
21→		return 0, err
22→	}
23→	defer stmt.Close()
24→
25→	count := 0
26→	for _, u := range updates {
27→		if u.ClassifiedBy == "" {
28→			u.ClassifiedBy = "claude"
29→		}
30→		res, err := stmt.Exec(u.Class, u.Confidence, u.ClassifiedBy, u.ID)
31→		if err != nil {
32→			return count, err
33→		}
34→		n, _ := res.RowsAffected()
35→		count += int(n)
36→	}
37→
38→	return count, tx.Commit()
39→}
