  3→import (
  4→	"database/sql"
  5→	"encoding/json"
  6→	"fmt"
  7→	"time"
  8→
  9→	"github.com/usenurge/nurgesh/internal/account"
 10→)
 11→
 12→// executionTables are tables where Convex is authoritative.
 13→// Pull direction: Convex → SQLite.
 14→var executionTables = []string{
 15→	"emails",
 16→	"mailboxes",
 17→	"mailbox_send_events",
 18→	"sequence_enrollments",
 19→	"follow_up_tasks",
 20→	"suppressions",
 21→	"reply_events",
 22→	"sequence_drafts",
 23→}
 24→
 25→// localTables are tables where SQLite is authoritative.
 26→// Push direction: SQLite → Convex.
 27→var localTables = []string{
 28→	"contacts",
 29→	"learnings",
 30→	"skill_versions",
 31→	"deals",
 32→}
 33→
 34→const batchSize = 500
 35→
 36→// SyncState tracks the last sync position per direction.
 37→type SyncState struct {
 38→	LastPullVersion int64  `json:"last_pull_version"`
 39→	LastPushAt      string `json:"last_push_at"`
 40→}
 41→
 42→// Engine handles bidirectional sync between SQLite and Convex.
 43→type Engine struct {
 44→	db     *sql.DB
 45→	client *account.ConvexClient
 46→	token  string
 47→}
 48→
 49→// NewEngine creates a sync engine.
 50→func NewEngine(db *sql.DB, client *account.ConvexClient, token string) *Engine {
 51→	return &Engine{db: db, client: client, token: token}
 52→}
 53→
 54→// PullResult contains stats from a pull operation.
 55→type PullResult struct {
 56→	TablesUpdated int
 57→	RowsUpserted  int
 58→}
 59→
 60→// PushResult contains stats from a push operation.
 61→type PushResult struct {
 62→	TablesScanned int
 63→	RowsPushed    int
 64→}
 65→
 66→// SyncResult contains stats from a full sync (pull + push).
 67→type SyncResult struct {
 68→	Pull PullResult
 69→	Push PushResult
 70→}
 71→
 72→// Sync performs a full sync: pull execution state, then push local state.
 73→func (e *Engine) Sync() (*SyncResult, error) {
 74→	pullResult, err := e.Pull()
 75→	if err != nil {
 76→		return nil, fmt.Errorf("pull failed: %w", err)
 77→	}
 78→
 79→	pushResult, err := e.Push()
 80→	if err != nil {
 81→		return nil, fmt.Errorf("push failed: %w", err)
 82→	}
 83→
 84→	return &SyncResult{Pull: *pullResult, Push: *pushResult}, nil
 85→}
 86→
 87→// Pull fetches execution state from Convex and upserts into SQLite.
 88→func (e *Engine) Pull() (*PullResult, error) {
 89→	state, err := e.loadSyncState()
 90→	if err != nil {
 91→		return nil, fmt.Errorf("loading sync state: %w", err)
 92→	}
 93→
 94→	resp, err := e.client.PullExecutionState(e.token, state.LastPullVersion)
 95→	if err != nil {
 96→		return nil, fmt.Errorf("pulling from Convex: %w", err)
 97→	}
 98→
 99→	result := &PullResult{}
100→	tablesUpdated := map[string]bool{}

100→	tablesUpdated := map[string]bool{}
101→
102→	for _, row := range resp.Rows {
103→		if err := e.upsertRow(row); err != nil {
104→			return nil, fmt.Errorf("upserting %s/%s: %w", row.Table, row.ID, err)
105→		}
106→		result.RowsUpserted++
107→		tablesUpdated[row.Table] = true
108→	}
109→	result.TablesUpdated = len(tablesUpdated)
110→
111→	if resp.SyncVersion > state.LastPullVersion {
112→		state.LastPullVersion = resp.SyncVersion
113→		if err := e.saveSyncState(state); err != nil {
114→			return nil, fmt.Errorf("saving sync state: %w", err)
115→		}
116→	}
117→
118→	return result, nil
119→}
120→
121→// Push sends local state changes to Convex.
122→func (e *Engine) Push() (*PushResult, error) {
123→	state, err := e.loadSyncState()
124→	if err != nil {
125→		return nil, fmt.Errorf("loading sync state: %w", err)
126→	}
127→
128→	result := &PushResult{}
129→	var allRows []account.SyncRow
130→
131→	for _, table := range localTables {
132→		rows, err := e.changedLocalRows(table, state.LastPushAt)
133→		if err != nil {
134→			return nil, fmt.Errorf("reading changed rows from %s: %w", table, err)
135→		}
136→		allRows = append(allRows, rows...)
137→		result.TablesScanned++
138→	}
139→
140→	// Also push email classifications (local authority for the classification field)
141→	classRows, err := e.changedEmailClassifications(state.LastPushAt)
142→	if err != nil {
143→		return nil, fmt.Errorf("reading changed email classifications: %w", err)
144→	}
145→	allRows = append(allRows, classRows...)
146→
147→	if len(allRows) == 0 {
148→		return result, nil
149→	}
150→
151→	// Push in batches
152→	for i := 0; i < len(allRows); i += batchSize {
153→		end := i + batchSize
154→		if end > len(allRows) {
155→			end = len(allRows)
156→		}
157→		batch := allRows[i:end]
158→
159→		resp, err := e.client.PushLocalState(e.token, batch)
160→		if err != nil {
161→			return nil, fmt.Errorf("pushing batch %d-%d: %w", i, end, err)
162→		}
163→
164→		// Update local sync_version from server response
165→		for id, version := range resp.Versions {
166→			for _, row := range batch {
167→				if row.ID == id {
168→					if err := e.updateSyncVersion(row.Table, id, version); err != nil {
169→						return nil, fmt.Errorf("updating sync_version for %s/%s: %w", row.Table, id, err)
170→					}
171→					break
172→				}
173→			}
174→		}
175→		result.RowsPushed += len(batch)
176→	}
177→
178→	state.LastPushAt = time.Now().UTC().Format(time.RFC3339)
179→	if err := e.saveSyncState(state); err != nil {
180→		return nil, fmt.Errorf("saving sync state: %w", err)
181→	}
182→
183→	return result, nil
184→}
185→
186→// upsertRow writes a Convex row into the local SQLite table.
187→func (e *Engine) upsertRow(row account.SyncRow) error {
188→	if len(row.Data) == 0 {
189→		return nil
190→	}
191→
192→	columns := []string{"id"}
193→	placeholders := []string{"?"}
194→	values := []any{row.ID}
195→	updateParts := []string{}
196→
197→	for col, val := range row.Data {
198→		columns = append(columns, col)
199→		placeholders = append(placeholders, "?")
200→		values = append(values, val)
201→		updateParts = append(updateParts, fmt.Sprintf("%s = excluded.%s", col, col))
202→	}
203→
204→	// Always set sync_version
205→	columns = append(columns, "sync_version")
206→	placeholders = append(placeholders, "?")
207→	values = append(values, row.Version)
208→	updateParts = append(updateParts, "sync_version = excluded.sync_version")
209→
210→	query := fmt.Sprintf(
211→		"INSERT INTO %s (%s) VALUES (%s) ON CONFLICT(id) DO UPDATE SET %s",
212→		row.Table,
213→		joinStrings(columns, ", "),
214→		joinStrings(placeholders, ", "),
215→		joinStrings(updateParts, ", "),
216→	)
217→
218→	_, err := e.db.Exec(query, values...)
219→	return err
220→}
221→
222→// changedLocalRows returns rows from a local-state table changed since lastPushAt.
223→func (e *Engine) changedLocalRows(table, lastPushAt string) ([]account.SyncRow, error) {
224→	var rows []account.SyncRow
225→
226→	query := fmt.Sprintf("SELECT * FROM %s", table)
227→	args := []any{}
228→	if lastPushAt != "" {
229→		query += " WHERE updated_at > ?"
230→		args = append(args, lastPushAt)
231→	}
232→
233→	sqlRows, err := e.db.Query(query, args...)
234→	if err != nil {
235→		return nil, err
236→	}
237→	defer sqlRows.Close()
238→
239→	cols, err := sqlRows.Columns()
240→	if err != nil {
241→		return nil, err
242→	}
243→
244→	for sqlRows.Next() {
245→		values := make([]any, len(cols))
246→		ptrs := make([]any, len(cols))
247→		for i := range values {
248→			ptrs[i] = &values[i]
249→		}
250→		if err := sqlRows.Scan(ptrs...); err != nil {
251→			return nil, err
252→		}
253→
254→		data := map[string]any{}
255→		var id string
256→		for i, col := range cols {
257→			if col == "id" {
258→				id = fmt.Sprintf("%v", values[i])
259→			}
260→			if col == "sync_version" {
261→				continue // don't push sync_version back
262→			}
263→			data[col] = values[i]
264→		}
265→
266→		rows = append(rows, account.SyncRow{
267→			Table: table,
268→			ID:    id,
269→			Data:  data,
270→		})
271→	}
272→
273→	return rows, sqlRows.Err()
274→}
