 71→
 72→// ParseYAML parses and validates a connector YAML definition.
 73→func ParseYAML(data []byte) (*YAMLConnector, error) {
 74→	var def YAMLConnector
 75→	if err := yaml.Unmarshal(data, &def); err != nil {
 76→		return nil, fmt.Errorf("parsing YAML: %w", err)
 77→	}
 78→	if err := validateDef(&def); err != nil {
 79→		return nil, err
 80→	}
 81→	// Defaults
 82→	if def.Tier == 0 {
 83→		def.Tier = 2
 84→	}
 85→	if def.Verify.Method == "" {
 86→		def.Verify.Method = "GET"
 87→	}
 88→	return &def, nil
 89→}
 90→
 91→func validateDef(d *YAMLConnector) error {
 92→	if d.SchemaVersion != 1 {
 93→		return fmt.Errorf("connector definition has unsupported schema_version: %d (expected 1)", d.SchemaVersion)
 94→	}
 95→	if d.ID == "" {
 96→		return fmt.Errorf("connector definition missing required field: id")
 97→	}
 98→	if d.Name == "" {
 99→		return fmt.Errorf("connector %q missing required field: name", d.ID)
100→	}
101→	if d.Type == "" {
102→		return fmt.Errorf("connector %q missing required field: type", d.ID)
103→	}
104→	if d.Auth.Method == "" {
105→		return fmt.Errorf("connector %q missing required field: auth.method", d.ID)
106→	}
107→
108→	switch d.Auth.Method {
109→	case "oauth2":
110→		if d.Auth.AuthorizeURL == "" {
111→			return fmt.Errorf("connector %q (oauth2) missing auth.authorize_url", d.ID)
112→		}
113→		if d.Auth.TokenURL == "" {
114→			return fmt.Errorf("connector %q (oauth2) missing auth.token_url", d.ID)
115→		}
116→	case "api_key":
117→		if d.Auth.Header == "" && d.Auth.QueryParam == "" {
118→			return fmt.Errorf("connector %q (api_key) missing auth.header or auth.query_param", d.ID)
119→		}
120→	case "basic":
121→		// valid — credentials resolved at connect time
122→	case "webhook":
123→		// valid — URL resolved at connect time
124→	default:
125→		return fmt.Errorf("connector %q has unknown auth.method: %q", d.ID, d.Auth.Method)
126→	}
127→
128→	return nil
129→}
