 85→// IsDirEmpty returns true if dir contains no entries except allowed ones
 86→// (.nurge, .git, .gitignore, .DS_Store, .claude).
 87→func IsDirEmpty(dir string) (bool, error) {
 88→	allowed := map[string]bool{
 89→		".nurge":     true,
 90→		".git":       true,
 91→		".gitignore": true,
 92→		".DS_Store":  true,
 93→		".claude":    true,
 94→	}
 95→
 96→	entries, err := os.ReadDir(dir)
 97→	if err != nil {
 98→		return false, err
 99→	}
100→	for _, e := range entries {
101→		name := strings.TrimSuffix(e.Name(), "/")
102→		if !allowed[name] {
103→			return false, nil
104→		}
105→	}
106→	return true, nil
107→}
