  1→package project
  2→
  3→import (
  4→	"fmt"
  5→	"os"
  6→	"path/filepath"
  7→	"strings"
  8→)
  9→
 10→// Options holds CLI flags for nurge init.
 11→type Options struct {
 12→	SkipHooks bool
 13→	Force     bool
 14→	Verbose   bool
 15→}
 16→
 17→// Step is the interface each init step implements.
 18→type Step interface {
 19→	Name() string
 20→	Done() (bool, error)
 21→	Run() error
 22→}
 23→
 24→// Run executes all init steps in order.
 25→func Run(opts Options) error {
 26→	fmt.Println()
 27→	fmt.Println("  nurge — outbound that learns")
 28→	fmt.Println()
 29→
 30→	steps := buildSteps(opts)
 31→
 32→	for _, s := range steps {
 33→		if !opts.Force {
 34→			done, err := s.Done()
 35→			if err != nil {
 36→				printFail(s.Name(), err)
 37→				return err
 38→			}
 39→			if done {
 40→				printSkip(s.Name())
 41→				continue
 42→			}
 43→		}
 44→
 45→		if err := s.Run(); err != nil {
 46→			printFail(s.Name(), err)
 47→			return err
 48→		}
 49→		printDone(s.Name())
 50→	}
 51→
 52→	return nil
 53→}
 54→
 55→func buildSteps(opts Options) []Step {
 56→	var steps []Step
 57→
 58→	steps = append(steps, &projectStep{})
 59→	steps = append(steps, &databaseStep{})
 60→	steps = append(steps, &gitignoreStep{})
 61→
 62→	if !opts.SkipHooks {
 63→		steps = append(steps, &hooksStep{})
 64→	}
 65→
 66→	steps = append(steps, &skillStep{})
 67→	steps = append(steps, &gitStep{})
 68→	steps = append(steps, &nextStepStep{})
 69→
 70→	return steps
 71→}
 72→
 73→func printDone(name string) {
 74→	fmt.Fprintf(os.Stdout, "  \033[32m✓\033[0m %s\n", name)
 75→}
 76→
 77→func printSkip(name string) {
 78→	fmt.Fprintf(os.Stdout, "  \033[32m✓\033[0m %s (already done)\n", name)
 79→}
 80→
 81→func printFail(name string, err error) {
 82→	fmt.Fprintf(os.Stderr, "  \033[31m✗\033[0m %s: %v\n", name, err)
 83→}
 84→
 85→// IsDirEmpty returns true if dir contains no entries except allowed ones
 86→// (.nurge, .git, .gitignore, .DS_Store, .claude).
 87→func IsDirEmpty(dir string) (bool, error) {
 88→	allowed := map[string]bool{
 89→		".nurge":     true,
 90→		".git":       true,
 91→		".gitignore": true,
 92→		".DS_Store":  true,
 93→		".claude":    true,
 94→	}
 95→
 96→	entries, err := os.ReadDir(dir)
 97→	if err != nil {
 98→		return false, err
 99→	}
100→	for _, e := range entries {
101→		name := strings.TrimSuffix(e.Name(), "/")
102→		if !allowed[name] {
103→			return false, nil
104→		}
105→	}
106→	return true, nil
107→}
108→
109→// IsNurgeProject returns true if dir contains a .nurge/ directory.
110→func IsNurgeProject(dir string) bool {
111→	info, err := os.Stat(filepath.Join(dir, ".nurge"))
112→	return err == nil && info.IsDir()
113→}
