169→func executeDispatch(srv *gm.Service, d *sql.DB, dispatch []sequence.DispatchTask) ([]dispatcherExecutionResult, error) {
170→	results := make([]dispatcherExecutionResult, 0, len(dispatch))
171→	for _, item := range dispatch {
172→		if !item.Ready {
173→			continue
174→		}
175→
176→		attemptedAt := timeNow()
177→		fromAddress := strings.TrimSpace(item.TransportEmail)
178→		if fromAddress == "" {
179→			fromAddress = strings.TrimSpace(item.SelectedMailboxEmail)
180→		}
181→		if fromAddress == "" {
182→			results = append(results, dispatcherExecutionResult{
183→				TaskID:       item.ID,
184→				ContactEmail: item.ContactEmail,
185→				MailboxEmail: item.SelectedMailboxEmail,
186→				Status:       "failed",
187→				Error:        "no transport address available for task",
188→			})
189→			continue
190→		}
191→
192→		sent, err := email.Send(srv, fromAddress, email.SendOptions{
193→			To:       item.ContactEmail,
194→			Subject:  dispatchSubject(item),
195→			Body:     item.RenderedBody,
196→			ThreadID: item.ThreadID,
197→		})
198→		if err != nil {
199→			if markErr := sequence.MarkTaskAttempt(d, item.ID, attemptedAt, err); markErr != nil {
200→				return results, markErr
201→			}
202→			if updateErr := sequence.UpdateTaskSendState(d, item.ID, sequence.TaskSendStatusFailed, "", "", err.Error()); updateErr != nil {
203→				return results, updateErr
204→			}
205→			if logErr := sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
206→				MailboxID:    item.SelectedMailboxID,
207→				EnrollmentID: item.EnrollmentID,
208→				TaskID:       item.ID,
209→				ContactEmail: item.ContactEmail,
210→				SendType:     item.SendType,
211→				Status:       "failed",
212→				Subject:      dispatchSubject(item),
213→				Error:        err.Error(),
214→				AttemptedAt:  attemptedAt,
215→			}); logErr != nil {
216→				return results, logErr
217→			}
218→			results = append(results, dispatcherExecutionResult{
219→				TaskID:       item.ID,
220→				ContactEmail: item.ContactEmail,
221→				MailboxEmail: item.SelectedMailboxEmail,
222→				Status:       "failed",
223→				Error:        err.Error(),
224→			})
225→			continue
226→		}
227→
228→		if err := sequence.MarkTaskAttempt(d, item.ID, attemptedAt, nil); err != nil {
229→			return results, err
230→		}
231→		if err := sequence.UpdateTaskSendState(d, item.ID, sequence.TaskSendStatusSent, sent.MessageID, "", ""); err != nil {
232→			return results, err
233→		}
234→		if err := sequence.RecordSend(d, item.SelectedMailboxID, item.SendType, attemptedAt); err != nil {
235→			return results, fmt.Errorf("email sent (message ID: %s) but failed to record mailbox usage: %w", sent.MessageID, err)
236→		}
237→		if err := email.StoreEmail(d, &email.RawMessage{
238→			ID:        sent.MessageID,
239→			Source:    "gmail",
240→			Direction: "outbound",
241→			ThreadID:  sent.ThreadID,
242→			Subject:   dispatchSubject(item),
243→			FromEmail: fromAddress,
244→			ToEmails:  recipientsJSON(item.ContactEmail),
245→			Date:      attemptedAt.UTC().Format(time.RFC3339),
246→			Labels:    `["SENT"]`,
247→		}); err != nil {
248→			return results, fmt.Errorf("email sent (message ID: %s) but failed to store local send state: %w", sent.MessageID, err)
249→		}
250→		if _, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
251→			TaskID:    item.ID,
252→			ThreadID:  sent.ThreadID,
253→			MessageID: sent.MessageID,
254→			MailboxID: item.SelectedMailboxID,
255→			SentAt:    attemptedAt,
256→		}); err != nil {
257→			return results, fmt.Errorf("email sent (message ID: %s) but failed to advance task %s: %w", sent.MessageID, item.ID, err)
258→		}
259→		if err := sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
260→			MailboxID:    item.SelectedMailboxID,
261→			EnrollmentID: item.EnrollmentID,
262→			TaskID:       item.ID,
263→			ContactEmail: item.ContactEmail,
264→			SendType:     item.SendType,
265→			Status:       "sent",
266→			Subject:      dispatchSubject(item),
267→			MessageID:    sent.MessageID,
268→			AttemptedAt:  attemptedAt,
269→		}); err != nil {
270→			return results, err
271→		}
272→
273→		results = append(results, dispatcherExecutionResult{
274→			TaskID:       item.ID,
275→			ContactEmail: item.ContactEmail,
276→			MailboxEmail: item.SelectedMailboxEmail,
277→			MessageID:    sent.MessageID,
278→			Status:       "sent",
279→		})
280→	}
281→	return results, nil
282→}
