150→func shortDate(value string) string {
151→	if value == "" {
152→		return value
153→	}
154→	if ts, err := time.Parse(time.RFC3339, value); err == nil {
155→		return ts.In(time.Local).Format("2006-01-02 15:04")
156→	}
157→	if len(value) >= 16 {
158→		return value[:16]
159→	}
160→	if len(value) >= 10 {
161→		return value[:10]
162→	}
163→	return value
164→}
165→
166→func joinRecipients(recipients []string) string {
167→	if len(recipients) == 0 {
168→		return "(unknown recipient)"
169→	}
170→	return strings.Join(recipients, ", ")
171→}
172→
173→func relativeDueStatus(value string, now time.Time) string {
174→	dueAt, err := time.Parse(time.RFC3339, value)
175→	if err != nil {
176→		return "due"
177→	}
178→
179→	delta := dueAt.Sub(now.UTC())
180→	if delta >= 0 {
181→		if delta < time.Minute {
182→			return "due soon"
183→		}
184→		if delta < time.Hour {
185→			return fmt.Sprintf("in %dm", int(delta.Round(time.Minute)/time.Minute))
186→		}
187→		if delta < 24*time.Hour {
188→			return fmt.Sprintf("in %dh", int(delta.Round(time.Hour)/time.Hour))
189→		}
190→		return fmt.Sprintf("in %dd", int(delta.Hours()/24))
191→	}
192→
193→	overdue := -delta
194→	if overdue < time.Hour {
195→		return fmt.Sprintf("%dm overdue", int(overdue.Round(time.Minute)/time.Minute))
196→	}
197→	if overdue < 24*time.Hour {
198→		return fmt.Sprintf("%dh overdue", int(overdue.Round(time.Hour)/time.Hour))
199→	}
200→	return fmt.Sprintf("%dd overdue", int(overdue.Hours()/24))
201→}
202→
