  9→type Campaign struct {
 10→	ID           string `json:"id"`
 11→	Name         string `json:"name"`
 12→	SequenceName string `json:"sequence_name"`
 13→	MailboxID    string `json:"mailbox_id"`
 14→	MailboxEmail string `json:"mailbox_email"`
 15→	Status       string `json:"status"`
 16→	Description  string `json:"description"`
 17→	CreatedAt    string `json:"created_at"`
 18→	UpdatedAt    string `json:"updated_at"`
 19→}
 20→
 21→func CreateCampaign(d *sql.DB, name, sequenceName, mailboxEmail, description string) (*Campaign, error) {
 22→	if d == nil {
 23→		return nil, fmt.Errorf("database is required")
 24→	}
 25→	name = strings.TrimSpace(name)
 26→	if name == "" {
 27→		return nil, fmt.Errorf("campaign name is required")
 28→	}
 29→	template, err := TemplateByName(d, sequenceName)
 30→	if err != nil {
 31→		return nil, err
 32→	}
 33→
 34→	mailboxID := ""
 35→	if strings.TrimSpace(mailboxEmail) != "" {
 36→		mailbox, err := mailboxByEmail(d, mailboxEmail)
 37→		if err != nil {
 38→			return nil, err
 39→		}
 40→		mailboxID = mailbox.ID
 41→	}
 42→
 43→	_, err = d.Exec(`
 44→		INSERT INTO campaigns (id, name, sequence_name, mailbox_id, status, description)
 45→		VALUES (?, ?, ?, ?, 'active', ?)
 46→		ON CONFLICT(name) DO UPDATE SET
 47→			sequence_name = excluded.sequence_name,
 48→			mailbox_id = excluded.mailbox_id,
 49→			description = excluded.description,
 50→			status = 'active',
 51→			updated_at = datetime('now')`,
 52→		newID("camp"), name, template.Name, mailboxID, description,
 53→	)
 54→	if err != nil {
 55→		return nil, err
 56→	}
 57→	return CampaignByName(d, name)
 58→}
 59→
 60→func ListCampaigns(d *sql.DB, status string, limit int) ([]Campaign, error) {
 61→	query := `
 62→		SELECT c.id, c.name, c.sequence_name, c.mailbox_id, COALESCE(m.email, ''), c.status, c.description, c.created_at, c.updated_at
 63→		FROM campaigns c
 64→		LEFT JOIN mailboxes m ON m.id = c.mailbox_id`
 65→	var args []any
 66→	if strings.TrimSpace(status) != "" {
 67→		query += ` WHERE c.status = ?`
 68→		args = append(args, status)
 69→	}
 70→	query += ` ORDER BY c.updated_at DESC, c.name ASC`
 71→	if limit > 0 {
 72→		query += fmt.Sprintf(" LIMIT %d", limit)
 73→	}
 74→
 75→	rows, err := d.Query(query, args...)
 76→	if err != nil {
 77→		return nil, err
 78→	}
 79→	defer rows.Close()
 80→
 81→	var campaigns []Campaign
 82→	for rows.Next() {
 83→		var item Campaign
 84→		if err := rows.Scan(&item.ID, &item.Name, &item.SequenceName, &item.MailboxID, &item.MailboxEmail, &item.Status, &item.Description, &item.CreatedAt, &item.UpdatedAt); err != nil {
 85→			return nil, err
 86→		}
 87→		campaigns = append(campaigns, item)
 88→	}
 89→	return campaigns, rows.Err()
 90→}
 91→
 92→func CampaignByName(d *sql.DB, name string) (*Campaign, error) {
 93→	name = strings.TrimSpace(name)
 94→	if name == "" {
 95→		return nil, fmt.Errorf("campaign name is required")
 96→	}
 97→	row := d.QueryRow(`
 98→		SELECT c.id, c.name, c.sequence_name, c.mailbox_id, COALESCE(m.email, ''), c.status, c.description, c.created_at, c.updated_at
 99→		FROM campaigns c
100→		LEFT JOIN mailboxes m ON m.id = c.mailbox_id
101→		WHERE lower(c.name) = lower(?)`,
102→		name,
103→	)
104→
105→	var item Campaign
106→	if err := row.Scan(&item.ID, &item.Name, &item.SequenceName, &item.MailboxID, &item.MailboxEmail, &item.Status, &item.Description, &item.CreatedAt, &item.UpdatedAt); err != nil {
107→		if err == sql.ErrNoRows {
108→			return nil, fmt.Errorf("campaign %q not found", name)
109→		}
110→		return nil, err
111→	}
112→	return &item, nil
113→}
