  1→package email
  2→
  3→import (
  4→	"database/sql"
  5→	"encoding/json"
  6→	"strings"
  7→)
  8→
  9→type Context struct {
 10→	TotalEmails    int              `json:"total_emails"`
 11→	OutboundCount  int              `json:"outbound_count"`
 12→	TopRecipients  []RecipientCount `json:"top_recipients"`
 13→	TopDomains     []DomainCount    `json:"top_domains"`
 14→	SendingPattern SendingPattern   `json:"sending_pattern"`
 15→	CommonSubjects []string         `json:"common_subjects"`
 16→}
 17→
 18→type RecipientCount struct {
 19→	Email string `json:"email"`
 20→	Count int    `json:"count"`
 21→}
 22→
 23→type DomainCount struct {
 24→	Domain string `json:"domain"`
 25→	Count  int    `json:"count"`
 26→}
 27→
 28→type SendingPattern struct {
 29→	MostActiveDay string  `json:"most_active_day"`
 30→	AvgPerDay     float64 `json:"avg_per_day"`
 31→	AvgPerWeek    float64 `json:"avg_per_week"`
 32→}
 33→
 34→func GenerateContext(d *sql.DB) (*Context, error) {
 35→	ctx := &Context{}
 36→
 37→	d.QueryRow("SELECT COUNT(*) FROM emails").Scan(&ctx.TotalEmails)
 38→	d.QueryRow("SELECT COUNT(*) FROM emails WHERE class = 'outbound'").Scan(&ctx.OutboundCount)
 39→
 40→	// Parse to_emails JSON to get actual recipient counts and domain counts
 41→	recipientCounts := make(map[string]int)
 42→	domainCounts := make(map[string]int)
 43→
 44→	rows, err := d.Query("SELECT to_emails FROM emails WHERE class = 'outbound'")
 45→	if err == nil {
 46→		defer rows.Close()
 47→		for rows.Next() {
 48→			var toJSON string
 49→			rows.Scan(&toJSON)
 50→			var addrs []string
 51→			if json.Unmarshal([]byte(toJSON), &addrs) == nil {
 52→				for _, addr := range addrs {
 53→					recipientCounts[addr]++
 54→					if parts := strings.SplitN(addr, "@", 2); len(parts) == 2 {
 55→						domainCounts[parts[1]]++
 56→					}
 57→				}
 58→			}
 59→		}
 60→	}
 61→
 62→	// Sort by count (top 10)
 63→	ctx.TopRecipients = topN(recipientCounts, 10, func(k string, v int) RecipientCount {
 64→		return RecipientCount{Email: k, Count: v}
 65→	})
 66→	ctx.TopDomains = topN(domainCounts, 10, func(k string, v int) DomainCount {
 67→		return DomainCount{Domain: k, Count: v}
 68→	})
 69→
 70→	// Sending pattern
 71→	d.QueryRow(`
 72→		SELECT CAST(COUNT(*) AS REAL) / MAX(1, JULIANDAY('now') - JULIANDAY(MIN(date)))
 73→		FROM emails WHERE class = 'outbound'`).Scan(&ctx.SendingPattern.AvgPerDay)
 74→	ctx.SendingPattern.AvgPerWeek = ctx.SendingPattern.AvgPerDay * 7
 75→
 76→	d.QueryRow(`
 77→		SELECT CASE CAST(strftime('%w', date) AS INTEGER)
 78→			WHEN 0 THEN 'Sunday' WHEN 1 THEN 'Monday' WHEN 2 THEN 'Tuesday'
 79→			WHEN 3 THEN 'Wednesday' WHEN 4 THEN 'Thursday' WHEN 5 THEN 'Friday'
 80→			WHEN 6 THEN 'Saturday' END
 81→		FROM emails WHERE class = 'outbound'
 82→		GROUP BY strftime('%w', date) ORDER BY COUNT(*) DESC LIMIT 1`).Scan(&ctx.SendingPattern.MostActiveDay)
 83→
 84→	// Recent outbound subjects
 85→	subRows, err := d.Query("SELECT subject FROM emails WHERE class = 'outbound' ORDER BY date DESC LIMIT 50")
 86→	if err == nil {
 87→		defer subRows.Close()
 88→		for subRows.Next() {
 89→			var subj string
 90→			subRows.Scan(&subj)
 91→			ctx.CommonSubjects = append(ctx.CommonSubjects, subj)
 92→		}
 93→	}
 94→
 95→	return ctx, nil
 96→}
 97→
 98→func topN[T any](counts map[string]int, n int, conv func(string, int) T) []T {
 99→	type kv struct {
100→		k string
101→		v int
102→	}
103→	var sorted []kv
104→	for k, v := range counts {
105→		sorted = append(sorted, kv{k, v})
106→	}
107→	for i := 0; i < len(sorted) && i < n; i++ {
108→		for j := i + 1; j < len(sorted); j++ {
109→			if sorted[j].v > sorted[i].v {
110→				sorted[i], sorted[j] = sorted[j], sorted[i]
111→			}
112→		}
113→	}
114→	result := make([]T, 0, n)
115→	for i := 0; i < len(sorted) && i < n; i++ {
116→		result = append(result, conv(sorted[i].k, sorted[i].v))
117→	}
118→	return result
119→}
120→

100→		result.Cursor, result.Cursor, result.Stored,
101→	)
102→
103→	return result, nil
104→}
105→
106→func StoreEmail(d *sql.DB, e *RawMessage) error {
107→	source := e.Source
108→	if source == "" {
109→		source = "gmail"
110→	}
111→	direction := e.Direction
112→	if direction == "" {
113→		direction = "outbound"
114→	}
115→
116→	isNewMessage := true
117→	var existing int
118→	err := d.QueryRow(`SELECT 1 FROM emails WHERE id = ?`, e.ID).Scan(&existing)
119→	if err == nil {
120→		isNewMessage = false
121→	} else if err != nil && err != sql.ErrNoRows {
122→		return err
123→	}
124→
125→	_, err = d.Exec(`
126→		INSERT INTO emails (id, source, direction, thread_id, subject, from_email, to_emails, cc_emails, date, snippet, body_preview, labels)
127→		VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
128→		ON CONFLICT(id) DO UPDATE SET
129→			source = excluded.source,
130→			direction = excluded.direction,
131→			subject = excluded.subject,
132→			snippet = excluded.snippet,
133→			body_preview = excluded.body_preview,
134→			labels = excluded.labels,
135→			synced_at = datetime('now')`,
136→		e.ID, source, direction, e.ThreadID, e.Subject, e.FromEmail, e.ToEmails, e.CcEmails,
137→		e.Date, e.Snippet, e.BodyPreview, e.Labels,
138→	)
139→	if err != nil {
140→		return err
141→	}
142→	return upsertContactsForMessage(d, source, direction, e, isNewMessage)
143→}
144→
145→func parseMessage(msg *gm.Message) *RawMessage {
146→	e := &RawMessage{
147→		ID:        msg.Id,
148→		Source:    "gmail",
149→		Direction: "outbound",
150→		ThreadID:  msg.ThreadId,
151→		Snippet:   msg.Snippet,
152→		CcEmails:  "[]",
153→		ToEmails:  "[]",
154→		Labels:    "[]",
155→	}
156→
157→	for _, h := range msg.Payload.Headers {
158→		switch h.Name {
159→		case "Subject":
160→			e.Subject = h.Value
161→		case "From":
162→			e.FromEmail = extractEmail(h.Value)
163→		case "To":
164→			e.ToEmails = emailsToJSON(h.Value)
165→		case "Cc":
166→			e.CcEmails = emailsToJSON(h.Value)
167→		case "Date":
168→			if t, err := time.Parse(time.RFC1123Z, h.Value); err == nil {
169→				e.Date = t.UTC().Format(time.RFC3339)
170→			} else if t, err := time.Parse("Mon, 2 Jan 2006 15:04:05 -0700", h.Value); err == nil {
171→				e.Date = t.UTC().Format(time.RFC3339)
172→			} else {
173→				e.Date = h.Value
174→			}
175→		}
176→	}
177→
178→	if len(msg.LabelIds) > 0 {
179→		labelsJSON, _ := json.Marshal(msg.LabelIds)
180→		e.Labels = string(labelsJSON)
181→	}
182→
183→	return e
184→}
185→
186→func upsertContactsForMessage(d *sql.DB, source, direction string, e *RawMessage, incrementCount bool) error {
187→	timestamp := e.Date
188→	if direction == "inbound" {
189→		return upsertContact(d, source, e.FromEmail, timestamp, incrementCount)
190→	}
191→
192→	recipients := append(parseRecipients(e.ToEmails), parseRecipients(e.CcEmails)...)
193→	for _, recipient := range recipients {
194→		if err := upsertContact(d, source, recipient, timestamp, incrementCount); err != nil {
195→			return err
196→		}
197→	}
198→	return nil
199→}
200→
201→func upsertContact(d *sql.DB, source, emailAddress, activityAt string, incrementCount bool) error {
202→	emailAddress = strings.ToLower(strings.TrimSpace(emailAddress))
203→	if emailAddress == "" {
204→		return nil
205→	}
206→	domain := ""
207→	parts := strings.SplitN(emailAddress, "@", 2)
208→	if len(parts) == 2 {
209→		domain = parts[1]
210→	}
211→
212→	_, err := d.Exec(`
213→		INSERT INTO contacts (id, source, email, domain, last_activity_at, email_count, last_emailed_at)
214→		VALUES (?, ?, ?, ?, ?, 1, ?)
215→		ON CONFLICT(source, email) DO UPDATE SET
216→			domain = CASE WHEN excluded.domain != '' THEN excluded.domain ELSE contacts.domain END,
217→			last_activity_at = CASE
218→				WHEN contacts.last_activity_at = '' OR contacts.last_activity_at IS NULL OR excluded.last_activity_at > contacts.last_activity_at THEN excluded.last_activity_at
219→				ELSE contacts.last_activity_at
220→			END,
221→			last_emailed_at = CASE
222→				WHEN contacts.last_emailed_at = '' OR contacts.last_emailed_at IS NULL OR excluded.last_emailed_at > contacts.last_emailed_at THEN excluded.last_emailed_at
223→				ELSE contacts.last_emailed_at
224→			END,
