276→// changedEmailClassifications returns emails with updated classifications.
277→func (e *Engine) changedEmailClassifications(lastPushAt string) ([]account.SyncRow, error) {
278→	query := `SELECT id, class, class_confidence, classified_by FROM emails WHERE class != 'unclassified'`
279→	args := []any{}
280→	if lastPushAt != "" {
281→		// Emails don't have updated_at, so push all classified emails on each push.
282→		// This is idempotent — Convex will ignore unchanged classifications.
283→	}
284→
285→	sqlRows, err := e.db.Query(query, args...)
286→	if err != nil {
287→		return nil, err
288→	}
289→	defer sqlRows.Close()
290→
291→	var rows []account.SyncRow
292→	for sqlRows.Next() {
293→		var id, class, classifiedBy string
294→		var confidence float64
295→		if err := sqlRows.Scan(&id, &class, &confidence, &classifiedBy); err != nil {
296→			return nil, err
297→		}
298→
299→		rows = append(rows, account.SyncRow{
300→			Table: "emails",
301→			ID:    id,
302→			Data: map[string]any{
303→				"class":            class,
304→				"class_confidence": confidence,
305→				"classified_by":    classifiedBy,
306→			},
307→		})
308→	}
309→
310→	return rows, sqlRows.Err()
311→}
312→
313→// updateSyncVersion sets the sync_version for a specific row.
314→func (e *Engine) updateSyncVersion(table, id string, version int64) error {
315→	query := fmt.Sprintf("UPDATE %s SET sync_version = ? WHERE id = ?", table)
316→	_, err := e.db.Exec(query, version, id)
317→	return err
318→}
319→
320→const syncStateKey = "_sync_state"
321→
322→// loadSyncState reads the sync cursor from a local config-like store.
323→func (e *Engine) loadSyncState() (*SyncState, error) {
324→	// Store sync state in a simple key-value row in connectors table (reusing existing table)
325→	var data string
326→	err := e.db.QueryRow(
327→		`SELECT sync_cursor FROM connectors WHERE id = ?`, syncStateKey,
328→	).Scan(&data)
329→	if err == sql.ErrNoRows {
330→		return &SyncState{}, nil
331→	}
332→	if err != nil {
333→		return nil, err
334→	}
335→
336→	var state SyncState
337→	if err := json.Unmarshal([]byte(data), &state); err != nil {
338→		return &SyncState{}, nil
339→	}
340→	return &state, nil
341→}
342→
343→// saveSyncState persists the sync cursor.
344→func (e *Engine) saveSyncState(state *SyncState) error {
345→	data, err := json.Marshal(state)
346→	if err != nil {
347→		return err
348→	}
349→
350→	_, err = e.db.Exec(`
351→		INSERT INTO connectors (id, type, sync_cursor)
352→		VALUES (?, 'sync', ?)
353→		ON CONFLICT(id) DO UPDATE SET sync_cursor = excluded.sync_cursor`,
354→		syncStateKey, string(data),
355→	)
356→	return err
357→}
