150→func calculateHealthScore(health MailboxHealth) int {
151→	score := health.Mailbox.ReputationScore
152→	if score == 0 {
153→		score = 100
154→	}
155→
156→	switch {
157→	case health.BounceStats.BounceRate >= 0.12:
158→		score -= 35
159→	case health.BounceStats.BounceRate >= 0.08:
160→		score -= 20
161→	case health.BounceStats.Bounces > 0:
162→		score -= 10
163→	}
164→
165→	if health.Mailbox.Status != "active" {
166→		score -= 20
167→	}
168→
169→	if health.DomainAuth != nil {
170→		if !health.DomainAuth.MXPresent {
171→			score -= 10
172→		}
173→		if !health.DomainAuth.SPFPresent {
174→			score -= 10
175→		}
176→		if !health.DomainAuth.DMARCPresent {
177→			score -= 10
178→		}
179→	}
180→
181→	if health.Mailbox.LastBounceAt != "" {
182→		if bouncedAt := parseOptionalTime(health.Mailbox.LastBounceAt); !bouncedAt.IsZero() && time.Since(bouncedAt) < 14*24*time.Hour {
183→			score -= 10
184→		}
185→	}
186→
187→	if score < 0 {
188→		return 0
189→	}
190→	if score > 100 {
191→		return 100
192→	}
193→	return score
194→}
195→
196→func healthRisk(score int) string {
197→	switch {
198→	case score >= 85:
199→		return "healthy"
200→	case score >= 65:
201→		return "watch"
202→	default:
203→		return "at-risk"
204→	}
205→}
206→
207→func warmupDay(mailbox Mailbox, now time.Time) int {
208→	startedAt := parseOptionalTime(mailbox.WarmupStartedAt)
209→	if startedAt.IsZero() {
210→		return 0
211→	}
212→	if now.UTC().Before(startedAt.UTC()) {
213→		return 0
214→	}
215→	return int(now.UTC().Sub(startedAt.UTC()).Hours() / 24)
216→}
