 10→type FollowUpTask struct {
 11→	ThreadID      string   `json:"thread_id"`
 12→	EmailID       string   `json:"email_id"`
 13→	Subject       string   `json:"subject"`
 14→	Recipients    []string `json:"recipients"`
 15→	LastSentAt    string   `json:"last_sent_at"`
 16→	DueAt         string   `json:"due_at"`
 17→	DaysSinceSent int      `json:"days_since_sent"`
 18→	DaysUntilDue  int      `json:"days_until_due"`
 19→}
 20→
 21→type FollowUpOptions struct {
 22→	AfterDays     int
 23→	Limit         int
 24→	IncludeFuture bool
 25→	Now           time.Time
 26→}
 27→
 28→type followUpRow struct {
 29→	ID       string
 30→	ThreadID string
 31→	Subject  string
 32→	ToEmails string
 33→	Date     string
 34→}
 35→
 36→// FollowUps returns one follow-up task per outbound thread based on the most
 37→// recent outbound email we have synced for that thread.
 38→func FollowUps(d *sql.DB, opts FollowUpOptions) ([]FollowUpTask, error) {
 39→	if opts.AfterDays <= 0 {
 40→		opts.AfterDays = 3
 41→	}
 42→	if opts.Now.IsZero() {
 43→		opts.Now = time.Now().UTC()
 44→	}
 45→
 46→	rows, err := d.Query(`
 47→		SELECT id, thread_id, subject, to_emails, date
 48→		FROM emails
 49→		WHERE class = 'outbound'
 50→		ORDER BY date DESC`)
 51→	if err != nil {
 52→		return nil, err
 53→	}
 54→	defer rows.Close()
 55→
 56→	seenThreads := make(map[string]bool)
 57→	var tasks []FollowUpTask
 58→
 59→	for rows.Next() {
 60→		var row followUpRow
 61→		if err := rows.Scan(&row.ID, &row.ThreadID, &row.Subject, &row.ToEmails, &row.Date); err != nil {
 62→			return nil, err
 63→		}
 64→		if seenThreads[row.ThreadID] {
 65→			continue
 66→		}
 67→		seenThreads[row.ThreadID] = true
 68→
 69→		lastSentAt, ok := parseStoredEmailTime(row.Date)
 70→		if !ok {
 71→			continue
 72→		}
 73→
 74→		dueAt := lastSentAt.AddDate(0, 0, opts.AfterDays)
 75→		if !opts.IncludeFuture && dueAt.After(opts.Now) {
 76→			continue
 77→		}
 78→
 79→		recipients := parseRecipients(row.ToEmails)
 80→		tasks = append(tasks, FollowUpTask{
 81→			ThreadID:      row.ThreadID,
 82→			EmailID:       row.ID,
 83→			Subject:       row.Subject,
 84→			Recipients:    recipients,
 85→			LastSentAt:    lastSentAt.UTC().Format(time.RFC3339),
 86→			DueAt:         dueAt.UTC().Format(time.RFC3339),
 87→			DaysSinceSent: wholeDaysBetween(lastSentAt, opts.Now),
 88→			DaysUntilDue:  wholeDaysBetween(opts.Now, dueAt),
 89→		})
 90→	}
 91→	if err := rows.Err(); err != nil {
 92→		return nil, err
 93→	}
 94→
 95→	sort.Slice(tasks, func(i, j int) bool {
 96→		if tasks[i].DueAt == tasks[j].DueAt {
 97→			return tasks[i].LastSentAt < tasks[j].LastSentAt
 98→		}
 99→		return tasks[i].DueAt < tasks[j].DueAt
100→	})
101→
102→	if opts.Limit > 0 && len(tasks) > opts.Limit {
103→		tasks = tasks[:opts.Limit]
104→	}
105→
106→	return tasks, nil
107→}
108→
109→func parseRecipients(raw string) []string {
110→	if raw == "" {
111→		return nil
112→	}
113→	var recipients []string
114→	if err := json.Unmarshal([]byte(raw), &recipients); err == nil {
115→		return recipients
116→	}
117→	return nil
118→}
119→
120→func parseStoredEmailTime(value string) (time.Time, bool) {
121→	layouts := []string{
122→		time.RFC3339,
123→		time.RFC1123Z,
124→		"Mon, 2 Jan 2006 15:04:05 -0700",
125→		"2006-01-02 15:04:05",
126→		"2006-01-02",
127→	}
128→
129→	for _, layout := range layouts {
130→		if ts, err := time.Parse(layout, value); err == nil {
131→			return ts.UTC(), true
132→		}
133→	}
134→
135→	return time.Time{}, false
136→}
137→
138→func wholeDaysBetween(from, to time.Time) int {
139→	return int(to.UTC().Sub(from.UTC()).Hours() / 24)
140→}
