401→func CanSend(d *sql.DB, mailboxID, sendType string, now time.Time) error {
402→	sendType = NormalizeSendType(sendType)
403→	if sendType == SendTypeManual {
404→		return nil
405→	}
406→	if now.IsZero() {
407→		now = time.Now()
408→	}
409→
410→	mailbox, usage, err := mailboxAndUsage(d, mailboxID, now)
411→	if err != nil {
412→		return err
413→	}
414→	if mailbox.Status != "active" {
415→		return fmt.Errorf("mailbox %s is %s", mailbox.Email, mailbox.Status)
416→	}
417→	if mailbox.ReputationScore > 0 && mailbox.ReputationScore < 40 {
418→		return fmt.Errorf("mailbox %s reputation is too low (%d)", mailbox.Email, mailbox.ReputationScore)
419→	}
420→	if !withinSendWindow(*mailbox, now) {
421→		return fmt.Errorf("mailbox %s is outside its send window (%s %02d:00-%02d:00)", mailbox.Email, mailbox.SendWindowTimezone, mailbox.SendWindowStartHour, mailbox.SendWindowEndHour)
422→	}
423→	if mailbox.LastBounceAt != "" && sendType == SendTypeFirstTouch {
424→		if bouncedAt, err := time.Parse(time.RFC3339, mailbox.LastBounceAt); err == nil && now.UTC().Before(bouncedAt.Add(24*time.Hour)) {
425→			return fmt.Errorf("mailbox %s is cooling off after a recent bounce until %s", mailbox.Email, bouncedAt.Add(24*time.Hour).Format(time.RFC3339))
426→		}
427→	}
428→	if bounceStats, err := mailboxBounceStats(d, mailboxID, now, 14); err == nil {
429→		switch {
430→		case bounceStats.Sends >= 10 && bounceStats.BounceRate >= 0.12:
431→			return fmt.Errorf("mailbox %s bounce rate is too high (%.1f%% over %d sends in %dd)", mailbox.Email, bounceStats.BounceRate*100, bounceStats.Sends, bounceStats.WindowDays)
432→		case sendType == SendTypeFirstTouch && bounceStats.Sends >= 10 && bounceStats.BounceRate >= 0.08:
433→			return fmt.Errorf("mailbox %s first touches are paused because bounce rate reached %.1f%% over the last %d days", mailbox.Email, bounceStats.BounceRate*100, bounceStats.WindowDays)
434→		}
435→	} else {
436→		return err
437→	}
438→
439→	firstTouchCap, followUpCap, replyCap := effectiveCaps(*mailbox, now)
440→
441→	switch sendType {
442→	case SendTypeFirstTouch:
443→		if firstTouchCap > 0 && usage.FirstTouchesSent >= firstTouchCap {
444→			return fmt.Errorf("mailbox %s has reached its first-touch daily cap (%d/%d)", mailbox.Email, usage.FirstTouchesSent, firstTouchCap)
445→		}
446→	case SendTypeFollowUp:
447→		if followUpCap > 0 && usage.FollowUpsSent >= followUpCap {
448→			return fmt.Errorf("mailbox %s has reached its follow-up daily cap (%d/%d)", mailbox.Email, usage.FollowUpsSent, followUpCap)
449→		}
450→	case SendTypeReply:
451→		if replyCap > 0 && usage.RepliesSent >= replyCap {
452→			return fmt.Errorf("mailbox %s has reached its reply daily cap (%d/%d)", mailbox.Email, usage.RepliesSent, replyCap)
453→		}
454→	}
455→
456→	if mailbox.MinGapMinutes > 0 {
457→		lastSentAt, err := latestMailboxOutboundAt(d, effectiveTransportEmail(*mailbox))
458→		if err != nil {
459→			return err
460→		}
461→		if !lastSentAt.IsZero() {
462→			nextAllowed := lastSentAt.Add(time.Duration(mailbox.MinGapMinutes) * time.Minute)
463→			if now.UTC().Before(nextAllowed) {
464→				return fmt.Errorf("mailbox %s is cooling down until %s", mailbox.Email, nextAllowed.Format(time.RFC3339))
465→			}
466→		}
467→	}
468→
469→	return nil
470→}
