472→func CreateEnrollmentAfterFirstTouch(d *sql.DB, opts EnrollmentOptions) (*Enrollment, *Task, error) {
473→	if opts.MailboxID == "" {
474→		return nil, nil, fmt.Errorf("mailbox ID is required")
475→	}
476→	if opts.ContactEmail == "" {
477→		return nil, nil, fmt.Errorf("contact email is required")
478→	}
479→	if opts.SentAt.IsZero() {
480→		opts.SentAt = time.Now()
481→	}
482→	if existing, err := ActiveEnrollmentForContact(d, opts.MailboxID, opts.ContactEmail); err != nil {
483→		return nil, nil, err
484→	} else if existing != nil {
485→		return nil, nil, fmt.Errorf("%s already has an active sequence enrollment (%s)", opts.ContactEmail, existing.ID)
486→	}
487→
488→	template, err := TemplateByName(d, opts.SequenceName)
489→	if err != nil {
490→		return nil, nil, err
491→	}
492→
493→	tx, err := d.Begin()
494→	if err != nil {
495→		return nil, nil, err
496→	}
497→	defer tx.Rollback()
498→
499→	enrollmentID := newID("seq")
500→	nextDue := ""
501→	var nextTask *Task
502→	if len(template.Steps) > 1 {
503→		nextDelay, err := stepDelay(template.Steps[1])
504→		if err != nil {
505→			return nil, nil, err
506→		}
507→		nextDueAt := opts.SentAt.Add(nextDelay).UTC()
508→		nextSubject, nextBody := renderStep(template.Steps[1], Enrollment{
509→			SequenceName: template.Name,
510→			CampaignName: defaultCampaignName(opts),
511→			MailboxID:    opts.MailboxID,
512→			ContactEmail: opts.ContactEmail,
513→			ContactName:  opts.ContactName,
514→			Subject:      opts.Subject,
515→			ThreadID:     opts.ThreadID,
516→			InitialBody:  opts.InitialBody,
517→		})
518→		nextDue = nextDueAt.Format(time.RFC3339)
519→		nextTask = &Task{
520→			ID:           newID("task"),
521→			EnrollmentID: enrollmentID,
522→			MailboxID:    opts.MailboxID,
523→			ContactEmail: opts.ContactEmail,
524→			Subject:      nextSubject,
525→			Body:         nextBody,
526→			ThreadID:     opts.ThreadID,
527→			StepNumber:   template.Steps[1].StepNumber,
528→			StepName:     template.Steps[1].Name,
529→			SendType:     template.Steps[1].SendType,
530→			Status:       TaskStatusOpen,
531→			DueAt:        nextDueAt.Format(time.RFC3339),
532→			SequenceName: template.Name,
533→		}
534→	}
535→
536→	_, err = tx.Exec(`
537→		INSERT INTO sequence_enrollments (
538→			id, sequence_name, campaign_name, mailbox_id, contact_email, contact_name, subject,
539→			thread_id, last_message_id, status, status_reason, reply_state, current_step, total_steps, last_sent_at, last_reply_at, next_due_at, initial_body
540→		) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
541→		enrollmentID, template.Name, defaultCampaignName(opts), opts.MailboxID, opts.ContactEmail, opts.ContactName,
542→		opts.Subject, opts.ThreadID, opts.MessageID, StatusActive, "", "", 1, len(template.Steps),
543→		opts.SentAt.UTC().Format(time.RFC3339), "", nextDue, opts.InitialBody,
544→	)
545→	if err != nil {
546→		return nil, nil, err
547→	}
548→
549→	if nextTask != nil {
550→		_, err = tx.Exec(`
551→			INSERT INTO follow_up_tasks (
552→				id, enrollment_id, mailbox_id, contact_email, subject, body, thread_id,
553→				step_number, step_name, send_type, status, send_status, due_at
554→			) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
555→			nextTask.ID, nextTask.EnrollmentID, nextTask.MailboxID, nextTask.ContactEmail,
556→			nextTask.Subject, nextTask.Body, nextTask.ThreadID, nextTask.StepNumber, nextTask.StepName,
557→			nextTask.SendType, nextTask.Status, TaskSendStatusPending, nextTask.DueAt,
558→		)
559→		if err != nil {
560→			return nil, nil, err
561→		}
562→		if err := UpsertDraftForTask(tx, nextTask.ID, nextTask.EnrollmentID, nextTask.StepNumber, nextTask.Subject, nextTask.Body, "sequence-runtime", "initial enrollment"); err != nil {
563→			return nil, nil, err
564→		}
565→	}
566→
567→	if err := tx.Commit(); err != nil {
568→		return nil, nil, err
569→	}
570→
571→	enrollment, err := EnrollmentByID(d, enrollmentID)
572→	if err != nil {
573→		return nil, nil, err
574→	}
575→
576→	if nextTask != nil {
577→		nextTask, err = TaskByID(d, nextTask.ID)
578→		if err != nil {
579→			return nil, nil, err
580→		}
581→	}
582→
583→	return enrollment, nextTask, nil
584→}
