586→func AdvanceTaskAfterSend(d *sql.DB, opts AdvanceOptions) (*Task, error) {
587→	if opts.TaskID == "" {
588→		return nil, fmt.Errorf("task ID is required")
589→	}
590→	if opts.SentAt.IsZero() {
591→		opts.SentAt = time.Now()
592→	}
593→
594→	task, err := TaskByID(d, opts.TaskID)
595→	if err != nil {
596→		return nil, err
597→	}
598→	if task.Status != TaskStatusOpen {
599→		return nil, fmt.Errorf("task %s is %s", task.ID, task.Status)
600→	}
601→
602→	enrollment, err := EnrollmentByID(d, task.EnrollmentID)
603→	if err != nil {
604→		return nil, err
605→	}
606→
607→	template, err := TemplateByName(d, enrollment.SequenceName)
608→	if err != nil {
609→		return nil, err
610→	}
611→
612→	tx, err := d.Begin()
613→	if err != nil {
614→		return nil, err
615→	}
616→	defer tx.Rollback()
617→
618→	_, err = tx.Exec(`
619→		UPDATE follow_up_tasks
620→		SET status = ?, send_status = ?, completed_at = ?, updated_at = datetime('now')
621→		WHERE id = ?`,
622→		TaskStatusCompleted, TaskSendStatusSent, opts.SentAt.UTC().Format(time.RFC3339), task.ID,
623→	)
624→	if err != nil {
625→		return nil, err
626→	}
627→	if err := UpdateDraftStatusByTaskID(tx, task.ID, "sent"); err != nil {
628→		return nil, err
629→	}
630→
631→	if task.StepNumber >= len(template.Steps) {
632→		_, err = tx.Exec(`
633→			UPDATE sequence_enrollments
634→			SET status = ?, current_step = ?, last_sent_at = ?, next_due_at = '',
635→				mailbox_id = CASE WHEN ? = '' THEN mailbox_id ELSE ? END,
636→				thread_id = CASE WHEN ? = '' THEN thread_id ELSE ? END,
637→				last_message_id = CASE WHEN ? = '' THEN last_message_id ELSE ? END,
638→				updated_at = datetime('now')
639→			WHERE id = ?`,
640→			StatusCompleted, task.StepNumber, opts.SentAt.UTC().Format(time.RFC3339),
641→			opts.MailboxID, opts.MailboxID,
642→			opts.ThreadID, opts.ThreadID, opts.MessageID, opts.MessageID, enrollment.ID,
643→		)
644→		if err != nil {
645→			return nil, err
646→		}
647→
648→		if err := tx.Commit(); err != nil {
649→			return nil, err
650→		}
651→		return nil, nil
652→	}
653→
654→	nextStep := template.Steps[task.StepNumber]
655→	nextDelay, err := stepDelay(nextStep)
656→	if err != nil {
657→		return nil, err
658→	}
659→	nextDueAt := opts.SentAt.Add(nextDelay).UTC()
660→	nextTaskID := newID("task")
661→	nextMailboxID := chooseString(opts.MailboxID, enrollment.MailboxID)
662→	nextThreadID := chooseString(opts.ThreadID, enrollment.ThreadID)
663→	renderEnrollment := *enrollment
664→	renderEnrollment.MailboxID = nextMailboxID
665→	renderEnrollment.ThreadID = nextThreadID
666→	renderEnrollment.LastMessageID = chooseString(opts.MessageID, enrollment.LastMessageID)
667→	nextSubject, nextBody := renderStep(nextStep, renderEnrollment)
668→
669→	_, err = tx.Exec(`
670→		INSERT INTO follow_up_tasks (
671→			id, enrollment_id, mailbox_id, contact_email, subject, body, thread_id,
672→			step_number, step_name, send_type, status, send_status, due_at
673→		) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
674→		nextTaskID, enrollment.ID, nextMailboxID, enrollment.ContactEmail,
675→		nextSubject, nextBody, nextThreadID, nextStep.StepNumber,
676→		nextStep.Name, nextStep.SendType, TaskStatusOpen, TaskSendStatusPending, nextDueAt.Format(time.RFC3339),
677→	)
678→	if err != nil {
679→		return nil, err
680→	}
681→	if err := UpsertDraftForTask(tx, nextTaskID, enrollment.ID, nextStep.StepNumber, nextSubject, nextBody, "sequence-runtime", "advance task"); err != nil {
682→		return nil, err
683→	}
684→
685→	_, err = tx.Exec(`
686→		UPDATE sequence_enrollments
687→		SET current_step = ?, last_sent_at = ?, next_due_at = ?,
688→			mailbox_id = CASE WHEN ? = '' THEN mailbox_id ELSE ? END,
689→			thread_id = CASE WHEN ? = '' THEN thread_id ELSE ? END,
690→			last_message_id = CASE WHEN ? = '' THEN last_message_id ELSE ? END,
691→			updated_at = datetime('now')
692→		WHERE id = ?`,
693→		task.StepNumber, opts.SentAt.UTC().Format(time.RFC3339), nextDueAt.Format(time.RFC3339),
694→		nextMailboxID, nextMailboxID,
695→		opts.ThreadID, opts.ThreadID, opts.MessageID, opts.MessageID, enrollment.ID,
696→	)
697→	if err != nil {
698→		return nil, err
699→	}

