 13→type LeadImportResult struct {
 14→	Imported          int      `json:"imported"`
 15→	Updated           int      `json:"updated"`
 16→	SkippedInvalid    int      `json:"skipped_invalid"`
 17→	SkippedDuplicate  int      `json:"skipped_duplicate"`
 18→	SkippedSuppressed int      `json:"skipped_suppressed"`
 19→	Errors            []string `json:"errors,omitempty"`
 20→}
