 22→func ImportLeadsCSV(d *sql.DB, path, source string) (*LeadImportResult, error) {
 23→	if d == nil {
 24→		return nil, fmt.Errorf("database is required")
 25→	}
 26→	if strings.TrimSpace(path) == "" {
 27→		return nil, fmt.Errorf("CSV file path is required")
 28→	}
 29→	if strings.TrimSpace(source) == "" {
 30→		source = "manual"
 31→	}
 32→
 33→	f, err := os.Open(path)
 34→	if err != nil {
 35→		return nil, err
 36→	}
 37→	defer f.Close()
 38→
 39→	reader := csv.NewReader(f)
 40→	reader.TrimLeadingSpace = true
 41→
 42→	header, err := reader.Read()
 43→	if err != nil {
 44→		return nil, err
 45→	}
 46→	index := map[string]int{}
 47→	for i, name := range header {
 48→		index[strings.ToLower(strings.TrimSpace(name))] = i
 49→	}
 50→	if _, ok := index["email"]; !ok {
 51→		return nil, fmt.Errorf("CSV must include an email column")
 52→	}
 53→
 54→	result := &LeadImportResult{}
 55→	seen := map[string]bool{}
 56→	for {
 57→		record, err := reader.Read()
 58→		if err == io.EOF {
 59→			break
 60→		}
 61→		if err != nil {
 62→			result.Errors = append(result.Errors, err.Error())
 63→			continue
 64→		}
 65→
 66→		email := strings.ToLower(strings.TrimSpace(csvValue(record, index, "email")))
 67→		if !strings.Contains(email, "@") {
 68→			result.SkippedInvalid++
 69→			continue
 70→		}
 71→		if seen[email] {
 72→			result.SkippedDuplicate++
 73→			continue
 74→		}
 75→		seen[email] = true
 76→
 77→		if _, suppressed, err := IsSuppressed(d, email); err != nil {
 78→			return nil, err
 79→		} else if suppressed {
 80→			result.SkippedSuppressed++
 81→			continue
 82→		}
 83→
 84→		name := strings.TrimSpace(csvValue(record, index, "name"))
 85→		company := strings.TrimSpace(csvValue(record, index, "company"))
 86→		title := strings.TrimSpace(csvValue(record, index, "title"))
 87→		owner := strings.TrimSpace(csvValue(record, index, "owner"))
 88→		phone := strings.TrimSpace(csvValue(record, index, "phone"))
 89→		leadStatus := strings.TrimSpace(csvValue(record, index, "lead_status"))
 90→		domain := strings.TrimSpace(csvValue(record, index, "domain"))
 91→		if domain == "" {
 92→			domain = domainFromEmail(email)
 93→		}
 94→
 95→		existingID, err := contactIDByEmail(d, email)
 96→		if err != nil && !isNotFound(err) {
 97→			return nil, err
 98→		}
 99→
100→		if existingID == "" {
101→			_, err = d.Exec(`
102→				INSERT INTO contacts (
103→					id, source, email, name, domain, company, title, phone, lead_status, owner, last_activity_at, updated_at
104→				) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
105→				newID("contact"), source, email, name, domain, company, title, phone, leadStatus, owner,
106→				time.Now().UTC().Format(time.RFC3339), time.Now().UTC().Format(time.RFC3339),
107→			)
108→			if err != nil {
109→				return nil, err
110→			}
111→			result.Imported++
112→			continue
113→		}
114→
115→		_, err = d.Exec(`
116→			UPDATE contacts
117→			SET source = CASE WHEN source = 'gmail' THEN source ELSE ? END,
118→				name = CASE WHEN ? = '' THEN name ELSE ? END,
119→				domain = CASE WHEN ? = '' THEN domain ELSE ? END,
120→				company = CASE WHEN ? = '' THEN company ELSE ? END,
121→				title = CASE WHEN ? = '' THEN title ELSE ? END,
122→				phone = CASE WHEN ? = '' THEN phone ELSE ? END,
123→				lead_status = CASE WHEN ? = '' THEN lead_status ELSE ? END,
124→				owner = CASE WHEN ? = '' THEN owner ELSE ? END,
125→				last_activity_at = ?,
126→				updated_at = ?
127→			WHERE id = ?`,
128→			source,
129→			name, name,
130→			domain, domain,
131→			company, company,
132→			title, title,
133→			phone, phone,
134→			leadStatus, leadStatus,
135→			owner, owner,
136→			time.Now().UTC().Format(time.RFC3339),
137→			time.Now().UTC().Format(time.RFC3339),
138→			existingID,
139→		)
140→		if err != nil {
141→			return nil, err
142→		}
143→		result.Updated++
144→	}
145→
146→	return result, nil
147→}
