157→func contactIDByEmail(d *sql.DB, email string) (string, error) {
158→	var id string
159→	err := d.QueryRow(`
160→		SELECT id
161→		FROM contacts
162→		WHERE lower(email) = lower(?)
163→		ORDER BY updated_at DESC
164→		LIMIT 1`,
165→		email,
166→	).Scan(&id)
167→	if err == sql.ErrNoRows {
168→		return "", fmt.Errorf("contact %s not found", email)
169→	}
170→	return id, err
171→}
