 75→func TemplateByName(d *sql.DB, name string) (Template, error) {
 76→	if strings.TrimSpace(name) == "" {
 77→		name = DefaultTemplateName
 78→	}
 79→	if template, ok := builtInTemplates[name]; ok {
 80→		return template, nil
 81→	}
 82→	if d == nil {
 83→		return Template{}, fmt.Errorf("unknown sequence template %q", name)
 84→	}
 85→
 86→	var stepsJSON string
 87→	err := d.QueryRow(`SELECT steps_json FROM sequence_templates WHERE lower(name) = lower(?)`, name).Scan(&stepsJSON)
 88→	if err == sql.ErrNoRows {
 89→		return Template{}, fmt.Errorf("unknown sequence template %q", name)
 90→	}
 91→	if err != nil {
 92→		return Template{}, err
 93→	}
 94→	return decodeTemplateSteps(name, stepsJSON)
 95→}
