 78→func mailboxBounceStats(d *sql.DB, mailboxID string, now time.Time, windowDays int) (BounceStats, error) {
 79→	if windowDays <= 0 {
 80→		windowDays = 14
 81→	}
 82→	stats := BounceStats{WindowDays: windowDays}
 83→
 84→	start := now.AddDate(0, 0, -windowDays).Format("2006-01-02")
 85→	if err := d.QueryRow(`
 86→		SELECT COALESCE(SUM(first_touches_sent + follow_ups_sent + replies_sent), 0)
 87→		FROM mailbox_daily_usage
 88→		WHERE mailbox_id = ? AND usage_day >= ?`,
 89→		mailboxID, start,
 90→	).Scan(&stats.Sends); err != nil {
 91→		return stats, err
 92→	}
 93→
 94→	if err := d.QueryRow(`
 95→		SELECT COUNT(*)
 96→		FROM reply_events
 97→		WHERE mailbox_id = ? AND classification = 'bounced' AND occurred_at >= ?`,
 98→		mailboxID, now.AddDate(0, 0, -windowDays).UTC().Format(time.RFC3339),
 99→	).Scan(&stats.Bounces); err != nil {
100→		return stats, err
101→	}
102→
103→	if stats.Sends > 0 {
104→		stats.BounceRate = float64(stats.Bounces) / float64(stats.Sends)
105→	}
106→
107→	return stats, nil
108→}
