24→// SaveFinal stores the user's final version and computes the diff.
25→func SaveFinal(db *sql.DB, draftID int64, userFinal string) error {
26→	// Get the original draft
27→	var aiDraft string
28→	err := db.QueryRow(`SELECT ai_draft FROM content_drafts WHERE id = ?`, draftID).Scan(&aiDraft)
29→	if err != nil {
30→		return fmt.Errorf("loading draft: %w", err)
31→	}
32→
33→	diff := computeDiff(aiDraft, userFinal)
34→	_, err = db.Exec(
35→		`UPDATE content_drafts SET user_final = ?, diff = ? WHERE id = ?`,
36→		userFinal, diff, draftID,
37→	)
38→	if err != nil {
39→		return fmt.Errorf("saving final: %w", err)
40→	}
41→	return nil
42→}
