44→// computeDiff produces a simple line-level diff summary.
45→// Not a full unified diff — just enough to see what changed.
46→func computeDiff(draft, final string) string {
47→	if draft == final {
48→		return "no changes"
49→	}
50→
51→	draftLines := strings.Split(draft, "\n")
52→	finalLines := strings.Split(final, "\n")
53→
54→	var changes []string
55→
56→	// Simple comparison: report added/removed/changed line counts
57→	added, removed, changed := 0, 0, 0
58→	maxLen := len(draftLines)
59→	if len(finalLines) > maxLen {
60→		maxLen = len(finalLines)
61→	}
62→
63→	for i := 0; i < maxLen; i++ {
64→		var dLine, fLine string
65→		if i < len(draftLines) {
66→			dLine = draftLines[i]
67→		}
68→		if i < len(finalLines) {
69→			fLine = finalLines[i]
70→		}
71→
72→		if dLine == "" && fLine != "" {
73→			added++
74→		} else if dLine != "" && fLine == "" {
75→			removed++
76→		} else if dLine != fLine {
77→			changed++
78→		}
79→	}
80→
81→	if added > 0 {
82→		changes = append(changes, fmt.Sprintf("+%d lines", added))
83→	}
84→	if removed > 0 {
85→		changes = append(changes, fmt.Sprintf("-%d lines", removed))
86→	}
87→	if changed > 0 {
88→		changes = append(changes, fmt.Sprintf("~%d lines changed", changed))
89→	}
90→
91→	if len(changes) == 0 {
92→		return "no changes"
93→	}
94→	return strings.Join(changes, ", ")
95→}
