708→func ListTasks(d *sql.DB, opts TaskListOptions) ([]Task, error) {
709→	if opts.Now.IsZero() {
710→		opts.Now = time.Now()
711→	}
712→
713→	query := `
714→		SELECT
715→			t.id, t.enrollment_id, e.sequence_name, e.campaign_name, t.mailbox_id, m.email,
716→			t.contact_email, t.subject, t.thread_id, t.step_number, t.step_name,
717→			t.send_type, t.status, t.due_at, t.body, t.send_status, t.last_attempt_at, t.last_error, t.attempt_count
718→		FROM follow_up_tasks t
719→		JOIN sequence_enrollments e ON e.id = t.enrollment_id
720→		JOIN mailboxes m ON m.id = t.mailbox_id
721→		WHERE t.status = ? AND e.status = ?`
722→	args := []any{TaskStatusOpen, StatusActive}
723→
724→	if !opts.IncludeFuture {
725→		query += " AND t.due_at <= ?"
726→		args = append(args, opts.Now.UTC().Format(time.RFC3339))
727→	}
728→
729→	query += " ORDER BY t.due_at ASC"
730→	if opts.Limit > 0 {
731→		query += fmt.Sprintf(" LIMIT %d", opts.Limit)
732→	}
733→
734→	rows, err := d.Query(query, args...)
735→	if err != nil {
736→		return nil, err
737→	}
738→	defer rows.Close()
739→
740→	var tasks []Task
741→	for rows.Next() {
742→		var task Task
743→		if err := rows.Scan(
744→			&task.ID, &task.EnrollmentID, &task.SequenceName, &task.CampaignName, &task.MailboxID,
745→			&task.MailboxEmail, &task.ContactEmail, &task.Subject, &task.ThreadID,
746→			&task.StepNumber, &task.StepName, &task.SendType, &task.Status, &task.DueAt,
747→			&task.Body, &task.SendStatus, &task.LastAttemptAt, &task.LastError, &task.AttemptCount,
748→		); err != nil {
749→			return nil, err
750→		}
751→		task.DaysUntilDue = daysUntil(task.DueAt, opts.Now)
752→		tasks = append(tasks, task)
753→	}
754→
755→	return tasks, rows.Err()
756→}
