765→func ListDispatchTasksForTransport(d *sql.DB, opts DispatchOptions) ([]DispatchTask, error) {
766→	if opts.Now.IsZero() {
767→		opts.Now = time.Now()
768→	}
769→
770→	tasks, err := ListTasks(d, TaskListOptions{
771→		IncludeFuture: false,
772→		Limit:         opts.Limit,
773→		Now:           opts.Now,
774→	})
775→	if err != nil {
776→		return nil, err
777→	}
778→
779→	dispatch := make([]DispatchTask, 0, len(tasks))
780→	for _, task := range tasks {
781→		item := DispatchTask{Task: task, Ready: true}
782→		if suppression, suppressed, err := IsSuppressed(d, task.ContactEmail); err != nil {
783→			return nil, err
784→		} else if suppressed {
785→			item.Ready = false
786→			item.BlockedReason = fmt.Sprintf("%s %s is suppressed (%s)", suppression.Scope, suppression.Value, suppression.Reason)
787→			dispatch = append(dispatch, item)
788→			continue
789→		}
790→
791→		mailbox, err := ResolveTaskMailbox(d, task, opts.TransportEmail, opts.Now)
792→		if err != nil {
793→			item.Ready = false
794→			item.BlockedReason = err.Error()
795→			dispatch = append(dispatch, item)
796→			continue
797→		}
798→		item.SelectedMailboxID = mailbox.ID
799→		item.SelectedMailboxEmail = mailbox.Email
800→		item.TransportEmail = effectiveTransportEmail(*mailbox)
801→		item.RenderedSubject, item.RenderedBody, err = RenderTaskContent(d, task)
802→		if err != nil {
803→			return nil, err
804→		}
805→		dispatch = append(dispatch, item)
806→	}
807→	return dispatch, nil
808→}
