840→func SnoozeTask(d *sql.DB, taskID string, byDays int) (*Task, error) {
841→	if byDays <= 0 {
842→		byDays = 1
843→	}
844→	task, err := TaskByID(d, taskID)
845→	if err != nil {
846→		return nil, err
847→	}
848→	if task.Status != TaskStatusOpen {
849→		return nil, fmt.Errorf("task %s is %s", task.ID, task.Status)
850→	}
851→
852→	dueAt, err := time.Parse(time.RFC3339, task.DueAt)
853→	if err != nil {
854→		return nil, fmt.Errorf("parsing due_at for task %s: %w", task.ID, err)
855→	}
856→	newDueAt := dueAt.AddDate(0, 0, byDays).UTC().Format(time.RFC3339)
857→
858→	_, err = d.Exec(`
859→		UPDATE follow_up_tasks
860→		SET due_at = ?, updated_at = datetime('now')
861→		WHERE id = ?`,
862→		newDueAt, task.ID,
863→	)
864→	if err != nil {
865→		return nil, err
866→	}
867→
868→	if _, err := d.Exec(`
869→		UPDATE sequence_enrollments
870→		SET next_due_at = ?, updated_at = datetime('now')
871→		WHERE id = ?`,
872→		newDueAt, task.EnrollmentID,
873→	); err != nil {
874→		return nil, err
875→	}
876→
877→	return TaskByID(d, task.ID)
878→}
