218→func maybeAutoSuppressDomainForBounces(tx *sql.Tx, contactEmail, reason string, occurredAt time.Time) error {
219→	domain := domainFromEmail(contactEmail)
220→	if domain == "" {
221→		return nil
222→	}
223→
224→	var bounceCount int
225→	if err := tx.QueryRow(`
