1598→func ResolveTaskMailbox(d *sql.DB, task Task, transportEmail string, now time.Time) (*Mailbox, error) {
1599→	if now.IsZero() {
1600→		now = time.Now()
1601→	}
1602→
1603→	primary, err := mailboxByID(d, task.MailboxID)
1604→	if err != nil {
1605→		return nil, err
1606→	}
1607→
1608→	if transportEmail == "" {
1609→		if err := CanSend(d, primary.ID, task.SendType, now); err != nil {
1610→			return nil, err
1611→		}
1612→		return primary, nil
1613→	}
1614→
1615→	candidates, err := rotationCandidates(d, *primary, task.SendType, transportEmail, now)
1616→	if err != nil {
1617→		return nil, err
1618→	}
1619→	if len(candidates) == 0 {
1620→		return nil, fmt.Errorf("no mailbox in rotation group %q is ready for transport %s", primary.RotationGroup, transportEmail)
1621→	}
1622→	return candidates[0], nil
1623→}
