1625→func rotationCandidates(d *sql.DB, primary Mailbox, sendType, transportEmail string, now time.Time) ([]*Mailbox, error) {
1626→	rows, err := d.Query(`
1627→		SELECT id, email, transport_email, rotation_group, provider, status, warmup_stage, warmup_started_at,
1628→			first_touch_daily_cap, follow_up_daily_cap, reply_daily_cap, min_gap_minutes,
1629→			send_window_start_hour, send_window_end_hour, send_window_timezone,
1630→			reputation_score, priority, last_used_at, last_bounce_at,
1631→			COALESCE(u.first_touches_sent, 0), COALESCE(u.follow_ups_sent, 0), COALESCE(u.replies_sent, 0)
1632→		FROM mailboxes
1633→		LEFT JOIN mailbox_daily_usage u
1634→			ON u.mailbox_id = mailboxes.id AND u.usage_day = ?
1635→		WHERE provider = ? AND rotation_group = ?
1636→		ORDER BY email ASC`,
1637→		dayKey(now), primary.Provider, primary.RotationGroup,
1638→	)
1639→	if err != nil {
1640→		return nil, err
1641→	}
1642→	defer rows.Close()
1643→
1644→	type candidate struct {
1645→		mailbox          *Mailbox
1646→		firstTouchesSent int
1647→		followUpsSent    int
1648→		repliesSent      int
1649→		remaining        int
1650→	}
1651→
1652→	var rawCandidates []candidate
1653→	blocked := map[string]string{}
1654→	for rows.Next() {
1655→		var item Mailbox
1656→		var firstTouchesSent, followUpsSent, repliesSent int
1657→		if err := rows.Scan(
1658→			&item.ID, &item.Email, &item.TransportEmail, &item.RotationGroup, &item.Provider, &item.Status, &item.WarmupStage, &item.WarmupStartedAt,
1659→			&item.FirstTouchDailyCap, &item.FollowUpDailyCap, &item.ReplyDailyCap, &item.MinGapMinutes,
1660→			&item.SendWindowStartHour, &item.SendWindowEndHour, &item.SendWindowTimezone,
1661→			&item.ReputationScore, &item.Priority, &item.LastUsedAt, &item.LastBounceAt,
1662→			&firstTouchesSent, &followUpsSent, &repliesSent,
1663→		); err != nil {
1664→			return nil, err
1665→		}
1666→		if !strings.EqualFold(effectiveTransportEmail(item), transportEmail) {
1667→			continue
1668→		}
1669→		rawCandidates = append(rawCandidates, candidate{
1670→			mailbox:          &item,
1671→			firstTouchesSent: firstTouchesSent,
1672→			followUpsSent:    followUpsSent,
1673→			repliesSent:      repliesSent,
1674→		})
1675→	}
1676→	if err := rows.Err(); err != nil {
1677→		return nil, err
1678→	}
1679→	if err := rows.Close(); err != nil {
1680→		return nil, err
1681→	}
1682→
1683→	candidates := make([]candidate, 0, len(rawCandidates))
1684→	for _, item := range rawCandidates {
1685→		if err := CanSend(d, item.mailbox.ID, sendType, now); err != nil {
1686→			blocked[item.mailbox.ID] = err.Error()
1687→			continue
1688→		}
1689→
1690→		firstTouchCap, followUpCap, replyCap := effectiveCaps(*item.mailbox, now)
1691→		switch NormalizeSendType(sendType) {
1692→		case SendTypeFirstTouch:
1693→			item.remaining = remaining(firstTouchCap, item.firstTouchesSent)
1694→		case SendTypeFollowUp:
1695→			item.remaining = remaining(followUpCap, item.followUpsSent)
1696→		case SendTypeReply:
1697→			item.remaining = remaining(replyCap, item.repliesSent)
1698→		default:
1699→			item.remaining = -1
1700→		}
1701→		candidates = append(candidates, item)
1702→	}
1703→
1704→	sort.SliceStable(candidates, func(i, j int) bool {
1705→		left := candidates[i]
1706→		right := candidates[j]
1707→		if left.mailbox.ID == primary.ID && right.mailbox.ID != primary.ID {
1708→			return true
1709→		}
1710→		if right.mailbox.ID == primary.ID && left.mailbox.ID != primary.ID {
1711→			return false
1712→		}
1713→		if left.mailbox.Priority != right.mailbox.Priority {
1714→			return left.mailbox.Priority > right.mailbox.Priority
1715→		}
1716→		if left.mailbox.ReputationScore != right.mailbox.ReputationScore {
1717→			return left.mailbox.ReputationScore > right.mailbox.ReputationScore
1718→		}
1719→		if left.remaining != right.remaining {
1720→			return left.remaining > right.remaining
1721→		}
1722→		leftUsed := parseOptionalTime(left.mailbox.LastUsedAt)
1723→		rightUsed := parseOptionalTime(right.mailbox.LastUsedAt)
1724→		if leftUsed.IsZero() != rightUsed.IsZero() {
1725→			return leftUsed.IsZero()
1726→		}
1727→		if !leftUsed.Equal(rightUsed) {
1728→			return leftUsed.Before(rightUsed)
1729→		}
1730→		return left.mailbox.Email < right.mailbox.Email
1731→	})
1732→
1733→	if len(candidates) == 0 {
1734→		if reason := blocked[primary.ID]; reason != "" {
1735→			return nil, fmt.Errorf("%s", reason)
1736→		}
1737→	}
1738→
1739→	result := make([]*Mailbox, 0, len(candidates))
1740→	for _, item := range candidates {
1741→		result = append(result, item.mailbox)
1742→	}
1743→	return result, nil
1744→}
