470→// --- Auto-update ---
471→
472→const (
473→	updateCacheFile = ".nurge/update_check.json"
474→	updateCheckTTL  = 24 * time.Hour
475→	githubReleasesURL = "https://api.github.com/repos/usenurge/nurge/releases/latest"
476→)
477→
478→type updateCache struct {
479→	LatestVersion string `json:"latest_version"`
480→	CheckedAt     string `json:"checked_at"`
481→	UpdatedAt     string `json:"updated_at,omitempty"`
482→}
483→
484→// checkAndAutoUpdate checks for updates (cached, 24h TTL) and auto-updates if needed.
485→// Returns a message for the banner, or empty string.
486→func checkAndAutoUpdate() string {
487→	// Read cache
488→	cache := readUpdateCache()
489→
490→	// If checked recently, just report
491→	if cache != nil && cache.CheckedAt != "" {
492→		checkedAt, err := time.Parse(time.RFC3339, cache.CheckedAt)
493→		if err == nil && time.Since(checkedAt) < updateCheckTTL {
494→			// Cache is fresh — check if we just updated
495→			if cache.UpdatedAt != "" {
496→				updatedAt, err := time.Parse(time.RFC3339, cache.UpdatedAt)
497→				if err == nil && time.Since(updatedAt) < 5*time.Minute {
498→					// Clear the updated flag for next time
499→					cache.UpdatedAt = ""
500→					writeUpdateCache(cache)
501→					return fmt.Sprintf("Updated to %s", cache.LatestVersion)
502→				}
503→			}
504→			return ""
505→		}
506→	}
507→
508→	// Check for latest version (with timeout)
509→	latest := fetchLatestVersion()
510→	if latest == "" {
511→		// Network failed — update cache timestamp so we don't retry immediately
512→		if cache == nil {
513→			cache = &updateCache{}
514→		}
515→		cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
516→		writeUpdateCache(cache)
517→		return ""
518→	}
519→
520→	// Save to cache
521→	if cache == nil {
522→		cache = &updateCache{}
523→	}
524→	cache.LatestVersion = latest
525→	cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
526→
527→	// Compare: if current version matches latest, no update needed
528→	if buildVersion == latest || buildVersion == latest[1:] { // handle v prefix
529→		writeUpdateCache(cache)
530→		return ""
531→	}
532→
533→	// Different version — auto-update
534→	if runAutoUpdate() {
535→		cache.UpdatedAt = time.Now().UTC().Format(time.RFC3339)
536→		writeUpdateCache(cache)
537→		return fmt.Sprintf("Updating to %s...", latest)
538→	}
539→
540→	writeUpdateCache(cache)
541→	return ""
542→}
543→
544→func readUpdateCache() *updateCache {
545→	data, err := os.ReadFile(updateCacheFile)
546→	if err != nil {
547→		return nil
548→	}
549→	var c updateCache
550→	if err := json.Unmarshal(data, &c); err != nil {
551→		return nil
552→	}
553→	return &c
554→}
555→
556→func writeUpdateCache(c *updateCache) {
557→	data, err := json.Marshal(c)
558→	if err != nil {
559→		return
560→	}
561→	os.MkdirAll(filepath.Dir(updateCacheFile), 0755)
562→	os.WriteFile(updateCacheFile, data, 0644)
563→}
564→
565→// fetchLatestVersion gets the latest release tag from GitHub. 3s timeout.
566→func fetchLatestVersion() string {
567→	client := &http.Client{Timeout: 3 * time.Second}
568→	resp, err := client.Get(githubReleasesURL)
569→	if err != nil {
570→		return ""
571→	}
572→	defer resp.Body.Close()
573→
574→	if resp.StatusCode != 200 {
575→		return ""
576→	}
577→
578→	var release struct {
579→		TagName string `json:"tag_name"`
580→	}
581→	if err := json.NewDecoder(resp.Body).Decode(&release); err != nil {
582→		return ""
583→	}
584→	return release.TagName
585→}
