313→// updateSyncVersion sets the sync_version for a specific row.
314→func (e *Engine) updateSyncVersion(table, id string, version int64) error {
315→	query := fmt.Sprintf("UPDATE %s SET sync_version = ? WHERE id = ?", table)
316→	_, err := e.db.Exec(query, version, id)
