319→
320→const syncStateKey = "_sync_state"
321→
322→// loadSyncState reads the sync cursor from a local config-like store.
323→func (e *Engine) loadSyncState() (*SyncState, error) {
324→	// Store sync state in a simple key-value row in connectors table (reusing existing table)
325→	var data string
326→	err := e.db.QueryRow(
327→		`SELECT sync_cursor FROM connectors WHERE id = ?`, syncStateKey,
328→	).Scan(&data)
329→	if err == sql.ErrNoRows {
330→		return &SyncState{}, nil
331→	}
332→	if err != nil {
333→		return nil, err
334→	}
335→
336→	var state SyncState
337→	if err := json.Unmarshal([]byte(data), &state); err != nil {
338→		return &SyncState{}, nil
339→	}
340→	return &state, nil
341→}
342→
343→// saveSyncState persists the sync cursor.
344→func (e *Engine) saveSyncState(state *SyncState) error {
345→	data, err := json.Marshal(state)
346→	if err != nil {
347→		return err
348→	}
349→
350→	_, err = e.db.Exec(`
351→		INSERT INTO connectors (id, type, sync_cursor)
352→		VALUES (?, 'sync', ?)
353→		ON CONFLICT(id) DO UPDATE SET sync_cursor = excluded.sync_cursor`,
354→		syncStateKey, string(data),
355→	)
356→	return err
357→}
