268→func recipientsJSON(raw string) string {
269→	raw = strings.TrimSpace(raw)
270→	if raw == "" {
271→		return "[]"
272→	}
273→	parts := strings.Split(raw, ",")
274→	recipients := make([]string, 0, len(parts))
275→	for _, part := range parts {
276→		part = strings.TrimSpace(part)
277→		if part != "" {
278→			recipients = append(recipients, part)
279→		}
280→	}
281→	data, _ := json.Marshal(recipients)
282→	return string(data)
283→}
