23→func (s *skillStep) Run() error {
24→	home, err := os.UserHomeDir()
25→	if err != nil {
26→		return fmt.Errorf("getting home dir: %w", err)
27→	}
28→
29→	skillDir := filepath.Join(home, ".claude", "skills", "nurge-setup")
30→	if err := os.MkdirAll(skillDir, 0755); err != nil {
31→		return fmt.Errorf("creating skill dir: %w", err)
32→	}
33→
34→	return fs.WalkDir(setupSkillFiles, "skills/setup", func(path string, d fs.DirEntry, err error) error {
35→		if err != nil {
36→			return err
37→		}
38→		if d.IsDir() {
39→			return nil
40→		}
41→
42→		content, err := setupSkillFiles.ReadFile(path)
43→		if err != nil {
44→			return fmt.Errorf("reading embedded %s: %w", path, err)
45→		}
46→
47→		destPath := filepath.Join(skillDir, d.Name())
48→		if err := os.WriteFile(destPath, content, 0644); err != nil {
49→			return fmt.Errorf("writing %s: %w", destPath, err)
50→		}
51→
52→		return nil
53→	})
